-- Poems batch 106
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bc6861c9-70c4-49fa-8bcc-fff42e705ff5','十二時歌  其九','釋印肅','宋','宋诗','song-poetry','','[]','黄昏戌，更點分明黑如漆。',60,'全唐诗/poet.song.121000.json','["黄昏戌，更點分明黑如漆。", "一道常光絕世倫，來往不通金密積。", "知不知，識不識，自古至今非外覓。", "木女清宵何所爲，混月閑吹無孔笛。"]'),
('ca36d309-b04b-489f-807f-7b70dc06b908','十二時歌  其一○','釋印肅','宋','宋诗','song-poetry','','[]','人定亥，墜石癡人猶擣碓。',60,'全唐诗/poet.song.121000.json','["人定亥，墜石癡人猶擣碓。", "忽然舂出古菱花，照地照天無向背。", "今時人，會不會，未了先須除渴愛。", "情忘想盡至無依，體若虛空非內外。"]'),
('d4437028-fda4-4165-a914-fd8c947e86db','十二時歌  其一一','釋印肅','宋','宋诗','song-poetry','','[]','夜半子，萬事無心誰到此。',60,'全唐诗/poet.song.121000.json','["夜半子，萬事無心誰到此。", "一毛頭上了徧圓，永劫不遭邪魅使。", "昇高臺，撾大鼓，努目摇頭如老虎。", "豬羊咬盡更傷人，自己不真長劫苦。"]'),
('07c33c98-0ae9-4755-9c25-bf112fb283aa','十二時歌  其一二','釋印肅','宋','宋诗','song-poetry','','[]','雞鳴丑，飛空著地波波走。',60,'全唐诗/poet.song.121000.json','["雞鳴丑，飛空著地波波走。", "演若達多再得頭，依前不換舊時首。", "無不無，有不有，有無不到休開口。", "拈槌豎拂有誰知，逐跡尋臊真獵狗。"]'),
('69198a71-58d3-42ae-a83b-8eee3f7330b9','頌石頭和尚草菴歌  其一','釋印肅','宋','宋诗','song-poetry','','[]','石頭和尚草菴歌，試問參方會也麽。',32,'全唐诗/poet.song.121000.json','["石頭和尚草菴歌，試問參方會也麽。", "千萬莫將茅瓦比，離鈎三寸綽清波。"]'),
('fa4a5143-b6c4-4051-9656-4c9445472f00','頌石頭和尚草菴歌  其二','釋印肅','宋','宋诗','song-poetry','','[]','吾結草菴無寶貝，日劫相陪誰曉會。',32,'全唐诗/poet.song.121000.json','["吾結草菴無寶貝，日劫相陪誰曉會。", "只緣窮子不歸家，未免出頭來捏怪。"]'),
('31f1bd33-4c57-47d9-8ddb-1c26e1f3bb99','頌石頭和尚草菴歌  其三','釋印肅','宋','宋诗','song-poetry','','[]','飯了從容圖睡快，杲日麗天無可曬。',32,'全唐诗/poet.song.121000.json','["飯了從容圖睡快，杲日麗天無可曬。", "薄𠜱輕霧沒虛空，飽塞虛空全不奈。"]'),
('02dc7199-bea0-4de3-bd03-7b6f09cf438f','頌石頭和尚草菴歌  其四','釋印肅','宋','宋诗','song-poetry','','[]','成時初見茅草新，權披百衲强看經。',32,'全唐诗/poet.song.121000.json','["成時初見茅草新，權披百衲强看經。", "賴得藥山重决破，別傳一句醒人心。"]'),
('7b0f2f79-1420-469c-b500-aed49759de01','頌石頭和尚草菴歌  其五','釋印肅','宋','宋诗','song-poetry','','[]','破後還將茅草蓋，雨過風吹無罣礙。',32,'全唐诗/poet.song.121000.json','["破後還將茅草蓋，雨過風吹無罣礙。", "垢衣那肯便拋遺，切恐眾生難理會。"]'),
('2f6b14f9-8d89-408e-8d2f-42061fddbe6a','頌石頭和尚草菴歌  其六','釋印肅','宋','宋诗','song-poetry','','[]','住菴人，體露堂堂非故新。',28,'全唐诗/poet.song.121000.json','["住菴人，體露堂堂非故新。", "毫髮有差魔道種，一塵不立妙通真。"]'),
('9a984c37-f254-4095-927c-078828a84012','頌石頭和尚草菴歌  其七','釋印肅','宋','宋诗','song-poetry','','[]','鎮長在，不是坐禪并禮拜。',28,'全唐诗/poet.song.121000.json','["鎮長在，不是坐禪并禮拜。", "實相元來豈用修，越古超今含法界。"]'),
('14332bd1-9d90-4718-8cbd-b0eb667a86b9','頌石頭和尚草菴歌  其八','釋印肅','宋','宋诗','song-poetry','','[]','不屬中間與內外，獨卧孤峰誰作對。',32,'全唐诗/poet.song.121000.json','["不屬中間與內外，獨卧孤峰誰作對。", "龍天百萬有誰知，金色頭陀笑裏會。"]'),
('36310ded-a2b4-477c-afa8-d48aad1bc6ba','頌石頭和尚草菴歌  其九','釋印肅','宋','宋诗','song-poetry','','[]','世人住處我不住，布施生天終陷墜。',32,'全唐诗/poet.song.121000.json','["世人住處我不住，布施生天終陷墜。", "靈光獨耀更無餘，未達凡夫開眼睡。"]'),
('540c55bd-2960-4ada-a4d0-62dc72d2c063','頌石頭和尚草菴歌  其一○','釋印肅','宋','宋诗','song-poetry','','[]','世人愛處我不愛，樂是苦因宜早退。',32,'全唐诗/poet.song.121000.json','["世人愛處我不愛，樂是苦因宜早退。", "六道四生何日休，唯大丈夫能氣概。"]'),
('8e82fcca-dba8-4106-8557-2e7ed5e0009b','頌石頭和尚草菴歌  其一一','釋印肅','宋','宋诗','song-poetry','','[]','菴雖小，寂寂寥寥勿邊表。',28,'全唐诗/poet.song.121000.json','["菴雖小，寂寂寥寥勿邊表。", "於中獨有一天真，透色融聲常皎皎。"]'),
('1d895ad5-3a0c-4ff4-8ef9-1dcd661323ad','頌石頭和尚草菴歌  其一二','釋印肅','宋','宋诗','song-poetry','','[]','含法界，大地須彌藏一芥。',28,'全唐诗/poet.song.121000.json','["含法界，大地須彌藏一芥。", "外道聲聞永不傳，究竟不如心自解。"]'),
('7de783eb-d1af-45e5-9529-a42a55d5e976','頌石頭和尚草菴歌  其一三','釋印肅','宋','宋诗','song-poetry','','[]','方丈老人相體解，一默全包無小大。',32,'全唐诗/poet.song.121000.json','["方丈老人相體解，一默全包無小大。", "曼殊贊歎實希奇，問疾不任知自敗。"]'),
('f3f7f39c-2bec-4c0d-b6c7-9d1107bc6dbf','頌石頭和尚草菴歌  其一四','釋印肅','宋','宋诗','song-poetry','','[]','上乘菩薩信無疑，爲法忘軀世所希。',32,'全唐诗/poet.song.121000.json','["上乘菩薩信無疑，爲法忘軀世所希。", "粉骨碎身應未報，聲聞小果卒難知。"]'),
('2801e1a5-b8a1-4932-9139-6908862e0881','頌石頭和尚草菴歌  其一五','釋印肅','宋','宋诗','song-poetry','','[]','中下聞之必生怪，泥有著無生死快。',32,'全唐诗/poet.song.121000.json','["中下聞之必生怪，泥有著無生死快。", "改頭換面者還來，歷劫茫茫虛受罪。"]'),
('0d64ac8b-1b08-4023-9edc-72e5de3335de','頌石頭和尚草菴歌  其一六','釋印肅','宋','宋诗','song-poetry','','[]','問此菴，有誰直下肯承當。',28,'全唐诗/poet.song.121000.json','["問此菴，有誰直下肯承當。", "不假良材並巧匠，重重帝綱妙嚴莊。"]'),
('e12bf141-21a9-4023-8f40-68292c40a039','頌石頭和尚草菴歌  其一七','釋印肅','宋','宋诗','song-poetry','','[]','壞不壞，百鍊金剛充法界。',28,'全唐诗/poet.song.121000.json','["壞不壞，百鍊金剛充法界。", "微塵不立似虛空，始得名爲觀自在。"]'),
('925fce53-cdc0-43b6-97a3-31c2e5179d5e','頌石頭和尚草菴歌  其一八','釋印肅','宋','宋诗','song-poetry','','[]','壞與不壞主元在，得未拳拳應不昧。',32,'全唐诗/poet.song.121000.json','["壞與不壞主元在，得未拳拳應不昧。", "婬坊酒肆轉光明，絕類離倫何窒礙。"]'),
('00e7198d-aedf-46a1-9143-37b1c610f1c0','頌石頭和尚草菴歌  其一九','釋印肅','宋','宋诗','song-poetry','','[]','不居南北與東西，萬法無生何所疑。',32,'全唐诗/poet.song.121000.json','["不居南北與東西，萬法無生何所疑。", "巖樹庭莎標妙相，猿啼鵲噪應真機。"]'),
('4c6ad971-1c62-44da-8e29-4ab3eee898b2','頌石頭和尚草菴歌  其二○','釋印肅','宋','宋诗','song-poetry','','[]','基址堅牢以爲最，百億輪鎚擊不開。',32,'全唐诗/poet.song.121000.json','["基址堅牢以爲最，百億輪鎚擊不開。", "定慧圓明非我所，方知達磨不曾來。"]'),
('25629609-79bc-4c80-bcd5-9c6dd1ef9630','頌石頭和尚草菴歌  其二一','釋印肅','宋','宋诗','song-poetry','','[]','青松下，珊珊遍地誰知價。',28,'全唐诗/poet.song.121000.json','["青松下，珊珊遍地誰知價。", "無限聰明只道空，問說真空沒命怕。"]'),
('43258fc6-2bb2-49c3-973f-3eb7078e26a4','頌石頭和尚草菴歌  其二二','釋印肅','宋','宋诗','song-poetry','','[]','明窗內，晃晃絕塵無覆草。',28,'全唐诗/poet.song.121000.json','["明窗內，晃晃絕塵無覆草。", "指作菩提却不真，白頂門開全領會。"]'),
('2ffbb0aa-7ac9-4c68-b60d-776e9204dacf','頌石頭和尚草菴歌  其二三','釋印肅','宋','宋诗','song-poetry','','[]','玉殿瓊樓未爲對，引慈眾生增渴愛。',32,'全唐诗/poet.song.121000.json','["玉殿瓊樓未爲對，引慈眾生增渴愛。", "放出溈山水牯牛，熒熒露地難遮蓋。"]'),
('67f8584f-2179-4555-808d-bb505b1bc27a','頌石頭和尚草菴歌  其二四','釋印肅','宋','宋诗','song-poetry','','[]','衲被蒙頭萬事休，九年面壁爲迷流。',32,'全唐诗/poet.song.121000.json','["衲被蒙頭萬事休，九年面壁爲迷流。", "神光斷臂何希有，薩埵投崖飼虎求。"]'),
('065af989-5536-4ff0-8e0d-a4c3ee13f30f','頌石頭和尚草菴歌  其二五','釋印肅','宋','宋诗','song-poetry','','[]','此時山僧都不會，猶若太虛無內外。',32,'全唐诗/poet.song.121000.json','["此時山僧都不會，猶若太虛無內外。", "臨時應化即非真，□取馳求還自背。"]'),
('2382b47d-ed31-451a-bf0a-e1cc66a77160','頌石頭和尚草菴歌  其二六','釋印肅','宋','宋诗','song-poetry','','[]','住此菴，不曾焚爇有爲香。',28,'全唐诗/poet.song.121000.json','["住此菴，不曾焚爇有爲香。", "終日示君君不見，更無餘事可思量。"]'),
('c757a48e-374a-4b3d-8895-de44ca995b52','頌石頭和尚草菴歌  其二七','釋印肅','宋','宋诗','song-poetry','','[]','休作解，眾妙玄玄無管带。',28,'全唐诗/poet.song.121000.json','["休作解，眾妙玄玄無管带。", "文殊仗劍逼如來，五百聲聞心豁解。"]'),
('25e12e22-8114-4b56-b345-66ce514d057f','頌石頭和尚草菴歌  其二八','釋印肅','宋','宋诗','song-poetry','','[]','誰誇鋪席圖人買，不用文章兼學解。',32,'全唐诗/poet.song.121000.json','["誰誇鋪席圖人買，不用文章兼學解。", "打破虛空歸去來，離世界兮入法界。"]'),
('4cc3b240-1204-4eb9-abbb-e9dbef74ae63','頌石頭和尚草菴歌  其二九','釋印肅','宋','宋诗','song-poetry','','[]','回光返照便歸來，鼻孔遼天眼豁開。',32,'全唐诗/poet.song.121000.json','["回光返照便歸來，鼻孔遼天眼豁開。", "元來佛法無多子，連𡎺三拳打自獃。"]'),
('1404473e-93d9-40f6-9225-02b008e8929b','頌石頭和尚草菴歌  其三○','釋印肅','宋','宋诗','song-poetry','','[]','廓達靈根非向背，不關南岳與天台。',32,'全唐诗/poet.song.121000.json','["廓達靈根非向背，不關南岳與天台。", "父母未生前一著，香嚴擊竹始迷開。"]'),
('1f0d4b71-95bd-4dea-9c33-cf4feccac705','頌石頭和尚草菴歌  其三一','釋印肅','宋','宋诗','song-poetry','','[]','遇祖師，不契玄機道愈疎。',28,'全唐诗/poet.song.121000.json','["遇祖師，不契玄機道愈疎。", "靈知不是目前法，目前無法可名模。"]'),
('76d0087b-3201-4b31-92db-54a882bc8a20','頌石頭和尚草菴歌  其三二','釋印肅','宋','宋诗','song-poetry','','[]','親訓誨，鈍斧開山百雜碎。',28,'全唐诗/poet.song.121000.json','["親訓誨，鈍斧開山百雜碎。", "不求諸聖入玄宗，雪點紅爐方稱對。"]'),
('a89cc40a-a97c-4bdb-97ef-213865b1e7f4','頌石頭和尚草菴歌  其三三','釋印肅','宋','宋诗','song-poetry','','[]','結草爲菴莫生退，百鳥銜花也不來。',32,'全唐诗/poet.song.121000.json','["結草爲菴莫生退，百鳥銜花也不來。", "花開還被風吹落，不得春風花不開。"]'),
('cb961519-8a89-4662-bba7-1b5204f26fa6','頌石頭和尚草菴歌  其三四','釋印肅','宋','宋诗','song-poetry','','[]','百年拋却任縱橫，隻履西歸表不生。',32,'全唐诗/poet.song.121000.json','["百年拋却任縱橫，隻履西歸表不生。", "來往本無常湛寂，心心相印號傳燈。"]'),
('cd16a4df-8c03-4383-bc5f-2a112038626c','頌石頭和尚草菴歌  其三五','釋印肅','宋','宋诗','song-poetry','','[]','擺手便行且無罪，汝等參方莫錯會。',32,'全唐诗/poet.song.121000.json','["擺手便行且無罪，汝等參方莫錯會。", "千古萬古一光明，不動遍周塵剎海。"]'),
('d034f09b-d367-449f-a5f0-d12f5bf6c3e3','頌石頭和尚草菴歌  其三六','釋印肅','宋','宋诗','song-poetry','','[]','千種言，修多羅教沒蹄筌。',28,'全唐诗/poet.song.121000.json','["千種言，修多羅教沒蹄筌。", "魚兔得時非在說，商人到岸不須船。"]'),
('447b721c-d4cc-46e7-8d3a-5ba028059b90','頌石頭和尚草菴歌  其三七','釋印肅','宋','宋诗','song-poetry','','[]','萬般解，筆寫石鎸處處賣。',28,'全唐诗/poet.song.121000.json','["萬般解，筆寫石鎸處處賣。", "不將一字與人依，露迥迥兮赤灑灑。"]'),
('e17df25a-40cc-4df1-81c5-29fc0f5ca226','頌石頭和尚草菴歌  其三八','釋印肅','宋','宋诗','song-poetry','','[]','只要教君長不昧，觸目無邊無對待。',32,'全唐诗/poet.song.121000.json','["只要教君長不昧，觸目無邊無對待。", "行住坐卧是誰來，提却蔓菁覓菘菜。"]'),
('90105390-e8db-493e-ac37-0f36a52d4a46','頌石頭和尚草菴歌  其三九','釋印肅','宋','宋诗','song-poetry','','[]','欲識菴中不死人，幾迴昏暗又天明。',32,'全唐诗/poet.song.121000.json','["欲識菴中不死人，幾迴昏暗又天明。", "明暗不來渠不動，周天匝地等空平。"]'),
('bd7fd7d0-68f7-4bd7-b7fc-c46869754326','頌石頭和尚草菴歌  其四○','釋印肅','宋','宋诗','song-poetry','','[]','豈離而今這皮袋，心法無形如大海。',32,'全唐诗/poet.song.121000.json','["豈離而今這皮袋，心法無形如大海。", "汪洋不宿死屍骸，萬古騰輝無變改。"]'),
('67110308-f34a-4599-aa3a-3bb8656e97b5','活人歌','釋印肅','宋','宋诗','song-poetry','','[]','大聖靈驗普菴圓，廣施含靈遇有緣。',256,'全唐诗/poet.song.121000.json','["大聖靈驗普菴圓，廣施含靈遇有緣。", "信心清浄通靈感，萬病俱銷釋業愆。", "文殊體，用普賢，活人歌裏現金仙。", "藥王藥上非他術，扁鵲孫真共一言。", "分三服，浄水煎，莫將血味污心田。", "萬物有形皆我體，但行慈德解讎冤。", "內無想，外無緣，何必神方肘後傳。", "身心本是金剛體，不解觀心被業纏。", "藥病銷，心月圓，信時佛豈獨西天。", "在在處處人皆有，世間無比這靈源。", "除罪垢，脫百冤，解使昏□朗義天。", "信知非我誰爲病，大士維摩笑裏眠。", "從生病，我不顛，體沒眾生我病痊。", "不二法門誰敢道，金毛師子露身全。", "速投藥，解塵緣，莫學群迷眼似聖。", "隨機應感非難易，信手拈來不用錢。"]'),
('789216e9-20f1-48ca-9d2b-d9e202450e40','洪鍾歌','釋印肅','宋','宋诗','song-poetry','','[]','昭文昭文施一鍾，懸空隨叩警盲聾。',286,'全唐诗/poet.song.121000.json','["昭文昭文施一鍾，懸空隨叩警盲聾。", "圓音不斷周沙界，純體金剛空不空。", "雖含響，擊即通，十方諸佛應聲中。", "天龍八部生忻悅，外道魔軍失却蹤。", "此圓器，大神功，上祝皇王壽不窮。", "日月長輝邦國靜，臣忠子孝續堯風。", "昏者醒，愚者聰，民歌鼓腹意和濃。", "地水火風同一性，剎塵無間體含融。", "包聲印頑空，鳥樹巖巒風月同。", "秦時何必驅山鐸，大振金鈴總脫空。", "時節至，自相逢，肯信無心達本宗。", "和同一族輸金玉，回向南泉鑄此鍾。", "黄昏裏，五更中，下下無空徹底通。", "近祖遠宗迷識解，聞歸浄土禮金容。", "涅槃侶，契心同，箇箇全音讚此功。", "顯理揚真無二聽，含靈蠢動一時通。", "受者法，施者空，且無地獄與洋銅。", "孝子順孫光遠慶，昭文千古振家風。"]'),
('c4d22743-20d5-45c3-87bb-58c2a4b8f3a0','開鍾示眾法語','釋印肅','宋','宋诗','song-poetry','','[]','總中有別異中同，成壞非干這一鍾。',32,'全唐诗/poet.song.121000.json','["總中有別異中同，成壞非干這一鍾。", "收拾油鐺并火熬，圓鎔法器隮盲聾。"]'),
('ea582cbc-8753-463e-8b99-0609f2f4fc33','學無學頌一十五首  其一','釋印肅','宋','宋诗','song-poetry','','[]','嘗聞學道不依形，道不依形不離形。',32,'全唐诗/poet.song.121000.json','["嘗聞學道不依形，道不依形不離形。", "不離不依猶寐語，尋思寐語本天真。"]'),
('98eba377-fb11-4927-ad35-d3934c31c387','學無學頌一十五首  其二','釋印肅','宋','宋诗','song-poetry','','[]','休道這邊與那邊，得時何更有枯偏。',30,'全唐诗/poet.song.121000.json','["休道這邊與那邊，得時何更有枯偏。", "有爲皆是夢，夢中明白體如然。"]'),
('f0c4725b-4e49-4bb7-8803-d55cca082752','學無學頌一十五首  其三','釋印肅','宋','宋诗','song-poetry','','[]','莫向人前說是非，是非不到實希奇。',32,'全唐诗/poet.song.121000.json','["莫向人前說是非，是非不到實希奇。", "假饒講得天花墜，大地山河總不知。"]'),
('da24e513-8988-4f06-a46d-5faf4286f463','學無學頌一十五首  其四','釋印肅','宋','宋诗','song-poetry','','[]','戴起枯髏撞眼睛，燒香設拜甚精勤。',32,'全唐诗/poet.song.121000.json','["戴起枯髏撞眼睛，燒香設拜甚精勤。", "一盲引眾誰人會，賺誤世間多少人。"]'),
('57964be3-0421-4548-8b7a-431a7feaa2de','學無學頌一十五首  其五','釋印肅','宋','宋诗','song-poetry','','[]','病在己而過在師，脫師離己悶胡蘆。',32,'全唐诗/poet.song.121000.json','["病在己而過在師，脫師離己悶胡蘆。", "從前學解皆忘却，撞頭磕腦愈心粗。"]'),
('4a26f731-ec0d-49a9-9936-ed7aef6df58c','學無學頌一十五首  其六','釋印肅','宋','宋诗','song-poetry','','[]','實見菩提說甚禪，大家打開過殘年。',32,'全唐诗/poet.song.121000.json','["實見菩提說甚禪，大家打開過殘年。", "相逢道伴何言語，無價真珠不用錢。"]'),
('2a43f824-4b26-4334-9c6c-4c6d51954edf','學無學頌一十五首  其七','釋印肅','宋','宋诗','song-poetry','','[]','達磨西來腦搭披，少林久坐若頑癡。',32,'全唐诗/poet.song.121000.json','["達磨西來腦搭披，少林久坐若頑癡。", "如斯顯赫非今古，唐土生靈誰得知。"]'),
('4202afd1-9aef-43c8-ac63-1ad514ba4a34','學無學頌一十五首  其八','釋印肅','宋','宋诗','song-poetry','','[]','老盧得了不傳衣，後代兒孫切莫疑。',32,'全唐诗/poet.song.121000.json','["老盧得了不傳衣，後代兒孫切莫疑。", "衣法親傳兩不是，心心心印了無知。"]'),
('e529c516-d087-401e-aac3-bc588039dec6','學無學頌一十五首  其九','釋印肅','宋','宋诗','song-poetry','','[]','五家示派亂縱橫，未到玄門語默爭。',32,'全唐诗/poet.song.121000.json','["五家示派亂縱橫，未到玄門語默爭。", "誑謗自招無間業，直須全體墜深坑。"]'),
('8214b99c-ca81-47f6-b29e-c03fb1453c91','學無學頌一十五首  其一○','釋印肅','宋','宋诗','song-poetry','','[]','奪下生機不作聲，耳聾眼瞎妙明生。',32,'全唐诗/poet.song.121000.json','["奪下生機不作聲，耳聾眼瞎妙明生。", "隨流只欲傳心印，豈是緣情粥飯僧。"]'),
('1b0a7b0d-411c-482d-b981-b731b5984853','學無學頌一十五首  其一一','釋印肅','宋','宋诗','song-poetry','','[]','昨夜三更日卓中，滿天星斗雨濛濛。',32,'全唐诗/poet.song.121000.json','["昨夜三更日卓中，滿天星斗雨濛濛。", "三門佛殿相携手，要去西天路不通。"]'),
('04b60d2c-dfc8-4b2c-a6a1-f7bdd47a2c9e','學無學頌一十五首  其一二','釋印肅','宋','宋诗','song-poetry','','[]','翠竹山茶映落霞，猿啼鵲噪道誰誇。',32,'全唐诗/poet.song.121000.json','["翠竹山茶映落霞，猿啼鵲噪道誰誇。", "一葉墜時秋遍界，春風微動一時花。"]'),
('eb34732a-ee31-4946-851c-36f3635d20bd','學無學頌一十五首  其一三','釋印肅','宋','宋诗','song-poetry','','[]','悟人寂寂心寥廓，迷者忙忙到處錯。',32,'全唐诗/poet.song.121000.json','["悟人寂寂心寥廓，迷者忙忙到處錯。", "普觀迷悟實無因，祇這如來大圓覺。"]'),
('c9329730-66d8-4b76-b18c-7adba855faf5','學無學頌一十五首  其一四','釋印肅','宋','宋诗','song-poetry','','[]','周歲孩兒八十翁，若觀老少絕宗風。',32,'全唐诗/poet.song.121000.json','["周歲孩兒八十翁，若觀老少絕宗風。", "眾生世界本無有，妙在當人一性中。"]'),
('a6dacdb3-3688-4e7c-afb7-55cbce31295e','學無學頌一十五首  其一五','釋印肅','宋','宋诗','song-poetry','','[]','十方世界口相吞，不斷圓音說普門。',32,'全唐诗/poet.song.121000.json','["十方世界口相吞，不斷圓音說普門。", "唯有普菴知說處，一箇窮人不著裩。"]'),
('48a191de-f8b4-4a53-b273-4363aeb53fa6','頌十玄談  其一','釋印肅','宋','宋诗','song-poetry','','[]','心心，非不心，未得印時生死侵。',31,'全唐诗/poet.song.121000.json','["心心，非不心，未得印時生死侵。", "除非一搭無纖翳，六道皆標我相形。"]'),
('28171ffa-f6ad-4099-a2fb-e3486ae47f42','頌十玄談  其二','釋印肅','宋','宋诗','song-poetry','','[]','祖祖，如鍾鼓，未擊有意周天普。',31,'全唐诗/poet.song.121000.json','["祖祖，如鍾鼓，未擊有意周天普。", "虛幻形聲本自無，如如不動亙今古。"]'),
('87d8bb80-34b9-4b5c-8375-2a7a27b35335','頌十玄談  其三','釋印肅','宋','宋诗','song-poetry','','[]','玄玄，不用言，機鋒相拄箭頭連。',31,'全唐诗/poet.song.121000.json','["玄玄，不用言，機鋒相拄箭頭連。", "達道無機玄不滿，儱侗真如有萬千。"]'),
('26f83cf9-7055-492b-ad6c-6ee41fb294a6','頌十玄談  其四','釋印肅','宋','宋诗','song-poetry','','[]','塵塵，背覺勞生地獄因。',27,'全唐诗/poet.song.121000.json','["塵塵，背覺勞生地獄因。", "鏡寫異形分皂白，合元一性自天真。"]'),
('a8125b55-4efb-4c54-a93a-39e9bedc29c0','頌十玄談  其五','釋印肅','宋','宋诗','song-poetry','','[]','演演，莫執文書案上展。',27,'全唐诗/poet.song.121000.json','["演演，莫執文書案上展。", "教人戒定慧堅牢，知見解脫堂堂顯。"]'),
('84364f26-c7fa-4516-8395-f245a14ed9fb','頌十玄談  其六','釋印肅','宋','宋诗','song-poetry','','[]','還還，不消下水及登山。',27,'全唐诗/poet.song.121000.json','["還還，不消下水及登山。", "左右逢源名實相，從斯周匝卧雲閑。"]'),
('bd11c793-4b4e-4978-b0b2-fdeb246d838d','頌十玄談  其七','釋印肅','宋','宋诗','song-poetry','','[]','達達，遍滿河沙微塵剎。',27,'全唐诗/poet.song.121000.json','["達達，遍滿河沙微塵剎。", "本來無語似陽春，雨過花枝連夜發。"]'),
('632ceba7-0fcb-42e4-afb1-292760b8a110','頌十玄談  其八','釋印肅','宋','宋诗','song-poetry','','[]','迴迴，目擊心通處處開。',27,'全唐诗/poet.song.121000.json','["迴迴，目擊心通處處開。", "機深體淺無人會，滿天風道我如來。"]'),
('459fe99f-c4b5-4a66-b5de-1f55f062ab69','頌十玄談  其九','釋印肅','宋','宋诗','song-poetry','','[]','轉轉，兩頭不著中心選。',27,'全唐诗/poet.song.121000.json','["轉轉，兩頭不著中心選。", "無位真人是阿誰，佛祖鼻孔穿成串。"]'),
('44a731e7-a150-4594-b0d5-59f361728d96','頌十玄談  其一○','釋印肅','宋','宋诗','song-poetry','','[]','一一，恰似太虛經鳥跡。',27,'全唐诗/poet.song.121000.json','["一一，恰似太虛經鳥跡。", "色即是空空不空，度日長吹無孔笛。"]'),
