('f52c82ed-f0ed-4808-9a4b-6c614507dda3','頌十玄談 迴機 其五','釋印肅','宋','宋诗','song-poetry','','[]','木人夜半穿靴去，得意生身無住處。',32,'全唐诗/poet.song.121000.json','["木人夜半穿靴去，得意生身無住處。", "妙用難傳妄想心，知君未解通方句。"]'),
('01422dbe-ec46-450a-8191-32532d611012','頌十玄談 迴機 其六','釋印肅','宋','宋诗','song-poetry','','[]','石女天明戴帽歸，一身渾著六銖衣。',32,'全唐诗/poet.song.121000.json','["石女天明戴帽歸，一身渾著六銖衣。", "喃喃解說非聲舌，生得兒來叫阿姨。"]'),
('231be57e-fe30-4ea9-8801-c2b46a168c37','頌十玄談 迴機 其七','釋印肅','宋','宋诗','song-poetry','','[]','萬古碧潭空界月，猿啼徹夜何曾歇。',32,'全唐诗/poet.song.121000.json','["萬古碧潭空界月，猿啼徹夜何曾歇。", "幾炙孤負一輪光，唯我同輝誰辨別。"]'),
('41dc6163-7155-472e-886a-b78e0e6ab504','頌十玄談 迴機 其八','釋印肅','宋','宋诗','song-poetry','','[]','再三撈摝始方知，捉影逃形也太癡。',32,'全唐诗/poet.song.121000.json','["再三撈摝始方知，捉影逃形也太癡。", "千眼大悲分得半，維摩老漢始全提。"]'),
('0afe3721-b620-41ed-812d-2ca292fe84eb','頌十玄談 轉位 其一','釋印肅','宋','宋诗','song-poetry','','[]','披毛戴角入廛來，水底桃花幾度開。',32,'全唐诗/poet.song.121000.json','["披毛戴角入廛來，水底桃花幾度開。", "世界未生唯此性，任他遷變豈輪迴。"]'),
('a5d2cd84-4f8c-4504-a236-ac8a2f9d2ffc','頌十玄談 轉位 其二','釋印肅','宋','宋诗','song-poetry','','[]','優鉢羅花火裏開，方知達磨不虛來。',32,'全唐诗/poet.song.121000.json','["優鉢羅花火裏開，方知達磨不虛來。", "夜來一霎清明雨，萬卉千葩勝剪裁。"]'),
('97c93188-eafa-4eb3-8280-6f26ba79d895','頌十玄談 轉位 其三','釋印肅','宋','宋诗','song-poetry','','[]','煩惱海中爲雨露，窮坑變作珍珠庫。',32,'全唐诗/poet.song.121000.json','["煩惱海中爲雨露，窮坑變作珍珠庫。", "可憐不識夜明簾，打破畫缾無作做。"]'),
('09afdb15-6e6d-46aa-b5ee-b016fea2f1f8','頌十玄談 轉位 其四','釋印肅','宋','宋诗','song-poetry','','[]','無明山中作雲雷，閃電霞光燦不開。',32,'全唐诗/poet.song.121000.json','["無明山中作雲雷，閃電霞光燦不開。", "霹靂一聲山嶽震，曼拏大士笑咍咍。"]'),
('64223338-e24a-425c-b49d-981d59073510','頌十玄談 轉位 其五','釋印肅','宋','宋诗','song-poetry','','[]','鑊湯爐炭吹教滅，一日三餐飽便歇。',32,'全唐诗/poet.song.121000.json','["鑊湯爐炭吹教滅，一日三餐飽便歇。", "獄卒牛頭惡夜叉，同氣連枝應不別。"]'),
('49b58861-68bc-4fc0-b63c-7918541e33cb','頌十玄談 轉位 其六','釋印肅','宋','宋诗','song-poetry','','[]','劍樹刀山喝使摧，十波羅蜜印靈臺。',32,'全唐诗/poet.song.121000.json','["劍樹刀山喝使摧，十波羅蜜印靈臺。", "光輪無盡奚邊表，不是貪嗔根得來。"]'),
('4d6f70dd-1b15-43b2-af93-3002aa83fe0d','頌十玄談 轉位 其七','釋印肅','宋','宋诗','song-poetry','','[]','金鎖玄關留不住，穿雲透石充寰宇。',32,'全唐诗/poet.song.121000.json','["金鎖玄關留不住，穿雲透石充寰宇。", "四時不語信寥寥，萬劫超然希伴侶。"]'),
('e63d817c-f859-4a0a-b8ff-006eccdcf9bd','頌十玄談 轉位 其八','釋印肅','宋','宋诗','song-poetry','','[]','行於異路且輪迴，百億分身撥不開。',32,'全唐诗/poet.song.121000.json','["行於異路且輪迴，百億分身撥不開。", "地獄天堂非別有，相呼相喚隱天台。"]'),
('7832b412-8d35-40be-a2cd-f7e7459ce7e8','頌十玄談 一色 其一','釋印肅','宋','宋诗','song-poetry','','[]','枯木巖前差路多，不行鳥道轉誵訛。',32,'全唐诗/poet.song.121000.json','["枯木巖前差路多，不行鳥道轉誵訛。", "狐狸引入豪豬窟，不久成團被死魔。"]'),
('8769b66b-f252-4b6a-9f11-88c2f208cbd3','頌十玄談 一色 其二','釋印肅','宋','宋诗','song-poetry','','[]','行人到此盡蹉跎，一指頭端不奈何。',32,'全唐诗/poet.song.121000.json','["行人到此盡蹉跎，一指頭端不奈何。", "毫髮有差千萬里，溈山撫掌笑呵呵。"]'),
('bf2e9b32-759b-4d6d-9cbf-db2757f521f1','頌十玄談 一色 其三','釋印肅','宋','宋诗','song-poetry','','[]','鷺鶿立雪非同色，鏡裏色空誰間隔。',32,'全唐诗/poet.song.121000.json','["鷺鶿立雪非同色，鏡裏色空誰間隔。", "不是青黄黑白紅，上下東西及南北。"]'),
('46b1b441-f0ac-42fe-b60c-3fc4602c377e','頌十玄談 一色 其四','釋印肅','宋','宋诗','song-poetry','','[]','明月蘆花不似他，於中一氣逼天羅。',32,'全唐诗/poet.song.121000.json','["明月蘆花不似他，於中一氣逼天羅。", "涅槃影裏無相識，鼻孔遼天笑大哥。"]'),
('62df1e9d-00a9-47ca-86f8-a3e09709c25a','頌十玄談 一色 其五','釋印肅','宋','宋诗','song-poetry','','[]','了了了時無可了，乾坤道我無邊表。',32,'全唐诗/poet.song.121000.json','["了了了時無可了，乾坤道我無邊表。", "燄摩宮裏混金風，兜率殿中明皎皎。"]'),
('a148e2e1-5d5b-48b8-8e40-32df832be701','頌十玄談 一色 其六','釋印肅','宋','宋诗','song-poetry','','[]','玄玄玄處亦須呵，喝斷烏江返碧波。',32,'全唐诗/poet.song.121000.json','["玄玄玄處亦須呵，喝斷烏江返碧波。", "寄語東吳諸父老，不如聞早念彌陀。"]'),
('ab89a352-70c8-4a2d-8d3a-e06e3b534711','頌十玄談 一色 其七','釋印肅','宋','宋诗','song-poetry','','[]','慇懃爲唱玄中曲，澗水相和音韻足。',32,'全唐诗/poet.song.121000.json','["慇懃爲唱玄中曲，澗水相和音韻足。", "唯有伯牙欲露機，斷絃深意無人續。"]'),
('640c0635-3a45-44b8-9f93-e13ad38b2af9','頌十玄談 一色 其八','釋印肅','宋','宋诗','song-poetry','','[]','空裏蟾光撮得麽，待風列子已蹉跎。',32,'全唐诗/poet.song.121000.json','["空裏蟾光撮得麽，待風列子已蹉跎。", "須彌無縫徒伸手，任是先天不奈何。"]'),
('2cdada6d-9d47-49b2-816f-a177296f492b','化米','釋印肅','宋','宋诗','song-poetry','','[]','當關擊破黄金鎖，佛與眾生無兩箇。',96,'全唐诗/poet.song.121000.json','["當關擊破黄金鎖，佛與眾生無兩箇。", "全提吞盡十方空，萬億龍天爲護佐。", "雪歌獨唱古峰頭，風月溪山同讚和。", "從來弘闡在當人，密賴知音共揚播。", "共揚播，非彼我，一鉢千家崇善果。", "直叩維摩不二門，狹路相逢休放過。"]'),
('2606a341-e43b-439a-a94f-006bd33bda21','買油','釋印肅','宋','宋诗','song-poetry','','[]','三百六十斤油，何須苦苦問他求。',63,'全唐诗/poet.song.121000.json','["三百六十斤油，何須苦苦問他求。", "心光廓徹燈何用，水草無心若畫牛。", "五味舌頭無足日，煎熬煮炙幾時休。", "功辨斯成無點染，西江一口絕纖流。"]'),
('a531d513-a811-448d-848d-6a7fda8c6e86','行童搬土','釋印肅','宋','宋诗','song-poetry','','[]','童子聚沙爲佛塔，而今搬土豈無功。',64,'全唐诗/poet.song.121000.json','["童子聚沙爲佛塔，而今搬土豈無功。", "忽然覺後知非土，當處回頭識本宗。", "老僧念你善根微，所以教伊不失時。", "朝歌暮擊三摩地，不久迷開解我機。"]'),
('5e101566-1118-4144-84c3-480640c20ea5','普請道友搬瓦','釋印肅','宋','宋诗','song-poetry','','[]','當時驢覷井，如今井覷驢。',76,'全唐诗/poet.song.121000.json','["當時驢覷井，如今井覷驢。", "酒醒溪邊思往昔，至今方覺彼區區。", "空花解弄□兒路，蝶引癡蜂入網蛛。", "誰是那頭能警叱，回光返照越賢愚。", "雲蓋瓦鋪須子細，筆端有口顯文殊。"]'),
('941a3b54-f69a-42e6-866a-123d7a2cb910','鐵竹歌','釋印肅','宋','宋诗','song-poetry','','[]','普菴和尚鐵竹歌，十聖三賢不奈何。',272,'全唐诗/poet.song.121000.json','["普菴和尚鐵竹歌，十聖三賢不奈何。", "九節玲瓏通法界，不由籩筍自嘍囉。", "從百鍊，已經磨，能障狂風止海波。", "惡龍攝毒皆由我，猛虎歸降豈是佗。", "世出世間無可比，非凡非聖力摩訶。", "莫耶劍，比天戈，生滅勞形費氣多。", "只這一條剛不壞，撐天拄地應三摩。", "身瑩浄，意曼陀，非眼耳鼻六通和。", "肉眼那能堪作見，二乘天眼尚誵訛。", "德山老漢却老婆，橫豎宗風般若多。", "罕遇其人難措手，至今獨卓立巍峨。", "君不見，莫蹉跎，點石爲金也是他。", "即栗橫肩千萬箇，解吞鐵竹可相過。", "未動口時百雜碎，豈同狐族唱巴歌。", "順天助道功非細，只欲令人脫死魔。", "喃喃解語非關舌，入水何曾動碧波。", "鐵竹自歌如是唱，海潮音徹笑呵呵。"]'),
('26a2e2be-978e-48b4-b095-13ce0fd8e12e','數珠歌','釋印肅','宋','宋诗','song-poetry','','[]','如是數珠祇一顆，離垢摩尼光不破。',368,'全唐诗/poet.song.121000.json','["如是數珠祇一顆，離垢摩尼光不破。", "佛說剎說眾生說，三世一切說這個。", "未了人，休將過，成佛人希念佛多。", "却將妄念數如麻，念來年久却成魔。", "假慈悲，當什麽，順時吉，逆時禍。", "行住坐卧似風牽，誑謗佛法如行貨。", "木槵子，麻穿過，假名一百單八箇。", "和酒和肉耀心光，誰覺死來連汝墮。", "心念肉，口波波，業識如是怎奈何。", "靈府未清徒念佛，身心浄土自彌陀。", "旃檀成，來惠我，拈起連天笑一和。", "自家不比這般人，黄葉止啼元是我。", "聰明人，猶較可，二乘聞說心如火。", "幾百劫中用數珠，今日教人都訣破。", "善男子，不恁麽，法無斷滅言無過。", "一人道假百千虛，何不學西來達磨。", "不立文字無唱和，寂滅光中神護佐。", "九年面壁沒人知，直指人心少林坐。", "雪齊腰，割臂墮，猶自惺惺不放過。", "徵詰神光勿得心，忽然解悟方擔荷。", "報參玄，休懡㦬，决擇身心是什麽。", "虛空何物可相當，體得一如閑打坐。", "十方諸佛念珠同，法界圓明無兩個。"]'),
('81797560-411b-414d-b4f6-10c0219e5e53','示弟子彭資深心齋居士','釋印肅','宋','宋诗','song-poetry','','[]','靈山話月，曹溪指月，禪可禪而成大過。',338,'全唐诗/poet.song.121000.json','["靈山話月，曹溪指月，禪可禪而成大過。", "一念頓超沒量人，六月雪哥向猛火。", "參方侶，休打坐，學至無學得什麽。", "自從打破趙州關，收放縱橫句不墮。", "這雪曲，誰解和，舉意萬機無兩個。", "拈題頌古若河沙，須是金毛師子子。", "這資深，被誰苦，夢中踢發千鈞弩。", "射過山河石壁空，枯髏爍盡無纖阻。", "希奇希奇誰得知，心空及第心齋子。", "古賢無限學無爲，罕遇明心輪劫苦。", "聞不聞，豈小補，識破天下老婆子。", "箭鋒相拄道應難，針芥相投萬事閑。", "不如佛祖只談心，悲愍盲參往別山。", "沒絃琴，誰會彈，盧公便就指風幡。", "直饒不是風幡動，不識真心轉見難。", "我意無盡非言說，離百非兮四句絕。", "首觀梁武夢胡僧，未達修山龍濟决。", "一百一十四重玄，大冶爐中撈片雪。", "生不生，滅不滅，萬法千機誰透徹。", "普菴不舍一微塵，本末雙彰□無說。", "肯將法界作紅心，一箭虛空渾漏泄。"]'),
('0586717d-a7e0-46df-8783-b9238c5404ee','達理歌','釋印肅','宋','宋诗','song-poetry','','[]','普菴識心達理，不是胡言亂語。',336,'全唐诗/poet.song.121000.json','["普菴識心達理，不是胡言亂語。", "教化三千大千，箇箇透泥入水。", "應無所住生心，更不祭神拜鬼。", "時中浄念法身，何假燒錢化紙。", "不被邪魔所惑，各各盡淘真理。", "亦非夜聚曉散，亦不遠尋山水。", "亦不發願燒香，亦不棄離妻子。", "不啗眾生血味，便敬六親九祖。", "誓不飲酒猖狂，不入牢獄苦楚。", "見利便不干心，處處如欽父母。", "你爭無明人我，我自無可作做。", "修橋補路隨緣，身作山河國土。", "供養大地含靈，上願皇圖永固。", "時時風調雨順，日日民歌樂舞。", "皆因自性天真，永不入他門戶。", "如今一物無求，不著邪魔祛使。", "不離當處湛然，運水搬柴佛事。", "何須打鐃擊鈸，豈用槌鐘擊鼓。", "饒舌合掌歸依，早被參方取怒。", "只心普遍蓮花，何異西方浄土。", "自古本自無迷，今本何曾有悟。", "設有三乘五教，也似添鹽和醋。", "生死涅槃如夢，佛說無所作做。", "更問達磨西來，他亦別無門路。"]'),
('358c2255-c47c-4415-9b9f-038b65905657','偈頌五首  其一','釋印肅','宋','宋诗','song-poetry','','[]','應目未嘗離左右，扣宗差別風馬牛。',32,'全唐诗/poet.song.121000.json','["應目未嘗離左右，扣宗差別風馬牛。", "遲速不停俱滯學，個裏還須自肯休。"]'),
('1a9ffbff-99a3-45bd-8c62-a67b6af253c5','偈頌五首  其二','釋印肅','宋','宋诗','song-poetry','','[]','議得無心達有心，識心三界自平沉。',32,'全唐诗/poet.song.121000.json','["議得無心達有心，識心三界自平沉。", "可憐迷望無心者，只道無心境不侵。"]'),
('8f244c40-8b77-48b0-ab3e-14e1573cc86b','偈頌五首  其三','釋印肅','宋','宋诗','song-poetry','','[]','有無俱不到，生滅豈相干。',24,'全唐诗/poet.song.121000.json','["有無俱不到，生滅豈相干。", "得者隨機應，未達莫顢頇。"]'),
('262f4c7f-0920-46f8-9a69-6f9db82e717b','偈頌五首  其四','釋印肅','宋','宋诗','song-poetry','','[]','體得寰中物，忘機自葆光。',48,'全唐诗/poet.song.121000.json','["體得寰中物，忘機自葆光。", "老莊言不及，佛祖句難藏。", "槁木非成道，灰心豈離忙。", "資深無欠少，本有不須忘。"]'),
('dda65f74-4cdc-4a24-bb31-25d98e61230f','偈頌五首  其五','釋印肅','宋','宋诗','song-poetry','','[]','南山北嶺如父母，張三李四皆佛祖。',32,'全唐诗/poet.song.121000.json','["南山北嶺如父母，張三李四皆佛祖。", "隨時只個無著相，許你住山一鈯斧。"]'),
('5d5434de-c3f9-4ed8-9a7c-ab51413a7716','紙被歌訓行童  其一','釋印肅','宋','宋诗','song-poetry','','[]','一片白雲掛在身，披時不許染紅塵。',158,'全唐诗/poet.song.121000.json','["一片白雲掛在身，披時不許染紅塵。", "輕羅細想應難比，重錦尋思未可親。", "豈非顔色白如玉，成現都盧只一幅。", "紅窗妖艷見低頭，六賊三尸盡降伏。", "日充衣，夜得蓋，不長不短也不大。", "世人問我何處尋，蔡倫弟子將來賣。", "買得將來披，不許邪魔罔兩知。", "解向市廛遮雲雨，要與閑人隔是非。", "縱顛狂，任落魄，披入村中人惡惡。", "直饒紫綬與金章，我也未肯輕輕博。"]'),
('897be83f-72d8-4cae-a25c-2b11ce61bd60','紙被歌訓行童  其二','釋印肅','宋','宋诗','song-poetry','','[]','皂袖寒袍入體儀，霞光閃爍遶身飛。',64,'全唐诗/poet.song.121000.json','["皂袖寒袍入體儀，霞光閃爍遶身飛。", "或行或坐頻頻看，或卧或眠每每披。", "幾度入山游勝境，數迴海上覓龍騎。", "假饒千兩黄金貴，難買山僧這個衣。"]'),
('11d30bb1-0a65-4e1e-90ef-0d3ba7f87237','大圓智鏡','釋印肅','宋','宋诗','song-poetry','','[]','普菴非相亦非名，達本忘情不見人。',128,'全唐诗/poet.song.121000.json','["普菴非相亦非名，達本忘情不見人。", "孤月全收無意識，桂輪獨耀絕纖塵。", "三祇一念湯消雪，萬行須臾火爍冰。", "到此何勞聲色問，共君本自鏡圓明。", "若將銅器作天真，背黑面青賺學人。", "本性如空含萬物，妙明寂照豈容塵。", "山河石壁三春霧，空色全彰六月冰。", "智自圓明非我所，不拘日月定光明。"]'),
('af315e59-2806-4820-ba54-e470da31d89e','與參徒辨事','釋印肅','宋','宋诗','song-poetry','','[]','仲元亨老，慇懃圓浄。',167,'全唐诗/poet.song.121000.json','["仲元亨老，慇懃圓浄。", "此中大事，雪曲高歌。", "騎白牛兒，漫空唱唱囉。", "這家也舂米，那畔爭打禾。", "且道乘誰力，天真大老婆。", "近日南方諸道友，斬釘截鐵自降魔。", "運水搬柴無不是，神通妙用顯摩訶。", "一人辦力諸天供，一會修來爭奈何。", "移根拔樹非邪作，翻有爲無萬事和。", "樓閣忽然橫碧漢，人人功德無空過。", "香積味憑知道者，須教不少亦非多。", "個裏不消重委囑，分明只是這彌陀。"]'),
('6a89ea36-98b3-4e7a-8d72-52dee7d5a995','因道友說陳摶打睡警之','釋印肅','宋','宋诗','song-poetry','','[]','日當午，有巴鼻，莫似這漢打瞌睡。',192,'全唐诗/poet.song.121000.json','["日當午，有巴鼻，莫似這漢打瞌睡。", "精魄沉滯識神牽，墮入三途難出離。", "我這裏，不如是，眼若不睡諸夢除。", "端然靜坐沒牽纏，縱橫自在無縈繫。", "學道人，生慚愧，普菴萬劫眼不閉。", "鼻孔連天叫大哥，海納細流通大意。", "勸君修，休退志，坐斷乾坤無別義。", "一條脊骨鍊純剛，撐天拄地更無二。", "這光明，全體是，充滿山河崇富貴。", "明月堂堂皎碧天，絕待靈明撒手去。", "一事無心了便休，祖門一句普天取。", "離相非空無別是，無聲之樂響啾啾。"]'),
('7a696cd6-d633-4ce3-ad3d-d2d05b0fd734','李光遠宅糴米','釋印肅','宋','宋诗','song-poetry','','[]','堪笑南泉老古錐，住山情况了無依。',86,'全唐诗/poet.song.121000.json','["堪笑南泉老古錐，住山情况了無依。", "解使木人來買米，和光風月正先知。", "奇奇，柳眼桃腮總是機。", "寸草不生千萬里，出門春色共依依。", "癡癡，三千不惜換驪珠。", "若問普菴來意處，光明遍匝體如如。"]'),
('72f338c7-12f5-4562-bce1-0dbf74c32ae6','與湯亨老居士','釋印肅','宋','宋诗','song-poetry','','[]','香積厨中烹五味，脚踏天兮頭頂地。',80,'全唐诗/poet.song.121000.json','["香積厨中烹五味，脚踏天兮頭頂地。", "雖然頭角各分張，未得箇人都了利。", "不然亨老大慈悲，一日無私和眾議。", "南方道友不偏枯，到裏許人皆具備。", "直教塞口併咽喉，消息出門無不是。"]'),
('82152a83-1bda-4480-9f85-4ad958bf9c50','贊三寶  其一','釋印肅','宋','宋诗','song-poetry','','[]','圓光應現無心物，大地山河恰似無。',32,'全唐诗/poet.song.121000.json','["圓光應現無心物，大地山河恰似無。", "驪珠一顆非非相，信者權將作畫圖。"]'),
('03ab9cc1-13b5-40fd-9511-dc4f533fb5e4','贊三寶  其二','釋印肅','宋','宋诗','song-poetry','','[]','直指人心親見佛，何勞打瓦作龜爻。',32,'全唐诗/poet.song.121000.json','["直指人心親見佛，何勞打瓦作龜爻。", "一片白雲橫谷口，幾多歸鳥盡迷巢。"]'),
('8976f120-3422-4ac4-a68b-06ceec38aa28','贊三寶  其三','釋印肅','宋','宋诗','song-poetry','','[]','迷悟本同光，信時無隱藏。',24,'全唐诗/poet.song.121000.json','["迷悟本同光，信時無隱藏。", "幻空如夢體，三昧覺華王。"]'),
('7c8f4173-7650-4ca2-b01c-6797e08b0ae7','贊達磨','釋印肅','宋','宋诗','song-poetry','','[]','妙契觸目菩提，誰觀達磨西歸。',44,'全唐诗/poet.song.121000.json','["妙契觸目菩提，誰觀達磨西歸。", "只是老胡捏怪，好與三十竹篦。", "試問參方知不知，狂書早自落便宜。"]'),
('d436638b-c505-4c11-a20a-ae7a0f8005eb','贊須菩提','釋印肅','宋','宋诗','song-poetry','','[]','伎倆全無始解空，雨花動地泄機鋒。',32,'全唐诗/poet.song.121000.json','["伎倆全無始解空，雨花動地泄機鋒。", "欲求靜坐無方所，獨步寥寥宇宙中。"]'),
('ad95ff7f-95a6-4272-9a7c-957f5d58493c','信士畫真請贊  其一','釋印肅','宋','宋诗','song-poetry','','[]','非迷非悟，誰强名模。',100,'全唐诗/poet.song.121000.json','["非迷非悟，誰强名模。", "無相三昧，不受塗糊。", "越色超聲無箇事，連聲不斷念蘇盧。", "眉芒動處千光含，自肯除非大丈夫。", "持心應不失，謀事便忘真。", "誰識元明寶，虛勞幾度春。", "因見普菴老，示我體皆純。", "但依無著性，性幻在逡巡。"]'),
('b6fe26ff-2684-4703-b22d-08601881dff3','信士畫真請贊  其二','釋印肅','宋','宋诗','song-poetry','','[]','普因乾坤非外物，周聞法界祇圓音。',96,'全唐诗/poet.song.121000.json','["普因乾坤非外物，周聞法界祇圓音。", "含靈入我身毛孔，非相非名何處尋。", "寶陀觸目無人見，妙體端嚴不壞金。", "如鐘含響隨緣應，見我方知識自心。", "釋迦佛，普菴光，不二如來體不藏。", "香花供養誰知有，只在眾生心印堂。"]'),
('ea1ca176-2485-431e-89cf-7aff84ab14da','信士畫真請贊  其三','釋印肅','宋','宋诗','song-poetry','','[]','此法身，無變壞，鼻孔裏許藏三界。',32,'全唐诗/poet.song.121000.json','["此法身，無變壞，鼻孔裏許藏三界。", "水月空花點不成，非相光中常自在。"]'),
('fed15615-66e7-4b37-b3b8-f33b1cbb68fb','信士畫真請贊  其四','釋印肅','宋','宋诗','song-poetry','','[]','法空爲座，金剛爲體，板如癡脫空無底。',28,'全唐诗/poet.song.121000.json','["法空爲座，金剛爲體，板如癡脫空無底。", "信心無二，吞山納水。"]'),
('d68c6a48-7fe9-43a4-9b96-21db90b91259','信士畫真請贊  其五','釋印肅','宋','宋诗','song-poetry','','[]','蒼天蒼天，悟無生法。',35,'全唐诗/poet.song.121000.json','["蒼天蒼天，悟無生法。", "談不說禪，開兩片皮。", "括地該天，如何是佛，十萬八千。"]'),
('0dbdadba-5f75-4793-91d9-d18d4d83e6db','信士畫真請贊  其六','釋印肅','宋','宋诗','song-poetry','','[]','易盡世間顔色，普菴頂相奚爲。',80,'全唐诗/poet.song.121000.json','["易盡世間顔色，普菴頂相奚爲。", "等大虛空一體，霧露雲霞表衣。", "眼觀不見，耳聽不知。", "惺惺不昧，了了何虧。", "自解拈花知起處，冷笑達磨更西歸。", "用晦隱顯無勞失，亙古亙今也大奇。"]'),
('10778750-b5a6-4b6a-b352-0d5d0762109a','示眾法語  其一','釋印肅','宋','宋诗','song-poetry','','[]','鑛去金存百鍊周，自從索價沒人酬。',64,'全唐诗/poet.song.121000.json','["鑛去金存百鍊周，自從索價沒人酬。", "騰今耀古非聲色，曾共溈山作牯牛。", "身若浮雲心若風，居常不定在虛空。", "忽然風捲雲無跡，誰人解識主人公。"]'),
('a51d7a37-e08d-4027-a202-1d5df6f36436','示眾法語  其二','釋印肅','宋','宋诗','song-poetry','','[]','大隱居廛小隱山，了心無事沒多般。',64,'全唐诗/poet.song.121000.json','["大隱居廛小隱山，了心無事沒多般。", "休緣到此磨塵垢，絕愛終須耐歲寒。", "百草上參多寶佛，鑊頭邊勘趙州關。", "莫教一擊連天地，震動坤維頃刻間。"]'),
('ee467a86-21b2-4beb-ac9a-eed9b200f8b9','示楊仲質','釋印肅','宋','宋诗','song-poetry','','[]','誰識一微塵，於中藏本佛。',60,'全唐诗/poet.song.121000.json','["誰識一微塵，於中藏本佛。", "時時常放光，照燭一切物。", "只許信心人，在處無輕忽。", "這回如未應，不離金剛骨。", "逢本分鉗鎚，煆成非外物。"]'),
('33f138bf-cbc6-4bd9-81ef-a441adaa57ca','和光讀金剛經以頌示之','釋印肅','宋','宋诗','song-poetry','','[]','道人看經不識字，剎那須轉千億部。',32,'全唐诗/poet.song.121000.json','["道人看經不識字，剎那須轉千億部。", "恒沙諸佛入微塵，達本契經無作做。"]'),
('d3d567c4-260f-4575-8478-024ba958ee01','何叔宜求頌','釋印肅','宋','宋诗','song-poetry','','[]','十力功高誰履踐，叔宜重叩普菴門。',64,'全唐诗/poet.song.121000.json','["十力功高誰履踐，叔宜重叩普菴門。", "玄玄眾妙靈知有，自肯唯心聞不聞。", "時信金剛通佛慧，情忘想盡合乾坤。", "夜月曉風消息滿，希夷獨步道常存。"]'),
('cff09bea-d1bd-433f-a748-0ba27bab936b','破屋頌示眾','釋印肅','宋','宋诗','song-poetry','','[]','一箇閑身穿破屋，風吹雨滴轉光明。',48,'全唐诗/poet.song.121000.json','["一箇閑身穿破屋，風吹雨滴轉光明。", "燈籠露柱時時舉，只道以平報不平。", "瑠璃殿上鞭金馬，追風不及三脚驢。"]'),
('3109bee3-60d4-40ec-9af0-b84ee76b80cd','衲衣示眾','釋印肅','宋','宋诗','song-poetry','','[]','一箇閑身包萬有，不能自把著針縫。',80,'全唐诗/poet.song.121000.json','["一箇閑身包萬有，不能自把著針縫。", "眾緣聚衲須微細，妙相莊嚴一大通。", "下下針鋒無不實，條條線貫不空空。", "連天鋪地山和水，一合圓成始脫籠。", "更有一般奇特處，巖前枯木笑春風。"]'),
('1be7ad31-ec69-425c-891b-f047ef31c753','示徒  其一','釋印肅','宋','宋诗','song-poetry','','[]','我有陀羅名解脫，在在處處和塵撥。',130,'全唐诗/poet.song.121000.json','["我有陀羅名解脫，在在處處和塵撥。", "莫令撥著箇凡夫，何用剃頭并展鉢。", "咦，連妻带子龐居士，一時成佛都包括。", "妄心不滅禍難除，任向祈求卜大虛。", "了道不消多語話，當軒自有顆明珠。", "半夜三更莫費油，澄潭捉月幾時休。", "冬年莫惹紅塵客，家道安然體自周。", "寄語門徒諸弟子，得心安樂外何求。"]'),
('afa7758a-e602-478e-8e0a-b9fc481339ba','示徒  其二','釋印肅','宋','宋诗','song-poetry','','[]','未得塵勞息，須依善知識。',168,'全唐诗/poet.song.121000.json','["未得塵勞息，須依善知識。", "若肯慈悲學，發願施心力。", "入泥并入水，莫作閑戲劇。", "揚眉動目庭，法身無窮極。", "於中習懶者，管取沒飯喫。", "趁隊只□飽，披毛無了日。", "不信佛乘經，逐末本却失。", "咄哉大丈夫，你乘誰氣力。", "當本無我人，貪忙有何益。", "何似歇無明，聽吹無孔笛。", "五音六律全，皓月悲風寂。", "一聲宇宙寬，箇中聞的實。", "和同爲智身，無物堪遮窒。", "奉勸草木影，閑時急收拾。"]'),
('63a96d30-268f-4efe-a9aa-54f4cbd18fd5','與夏國舅','釋印肅','宋','宋诗','song-poetry','','[]','白日上昇非偶爾，剎那成佛亦如然。',80,'全唐诗/poet.song.121000.json','["白日上昇非偶爾，剎那成佛亦如然。", "個中迥超聲色外，恩光滿目意連天。", "好明廓徹非思量，一受皇書遍普賢。", "江西風月光無盡，帝里真如萬法圓。", "當處飲吞無不足，護持秘密不休年。"]'),
('b9fe29e1-01fd-4376-a777-7ebe25a9ece8','與王巡檢  其一','釋印肅','宋','宋诗','song-poetry','','[]','佛法從來付宰臣，今朝已遇大心人。',32,'全唐诗/poet.song.121000.json','["佛法從來付宰臣，今朝已遇大心人。", "透明幻住超生滅，鑒物無私佑聖庭。"]'),
('18014fa6-fa95-4ead-9b25-ecbc184131e7','與王巡檢  其二','釋印肅','宋','宋诗','song-poetry','','[]','達磨非爲後，瞿曇未是先。',24,'全唐诗/poet.song.121000.json','["達磨非爲後，瞿曇未是先。", "當來無量劫，懶翁得自然。"]'),
('bfddecea-fb6d-48c9-a0cf-35661e5e6803','與廖維高','釋印肅','宋','宋诗','song-poetry','','[]','精通三教越禪機，語默同風和者希。',32,'全唐诗/poet.song.121000.json','["精通三教越禪機，語默同風和者希。", "匝地周天居士眼，元來只在一毫釐。"]'),
('2cdd1a05-68e8-4d37-b414-b06d66b1a1e9','資深和光求頌','釋印肅','宋','宋诗','song-poetry','','[]','同心實步叩南泉，雲節空巖廓杳然。',32,'全唐诗/poet.song.121000.json','["同心實步叩南泉，雲節空巖廓杳然。", "一室清風千古意，自非聲色問玄玄。"]'),
('692ec05a-88e7-4ff4-a6e0-5ebb58b6c917','示行者','釋印肅','宋','宋诗','song-poetry','','[]','絕頂無人處，融會亦非難。',56,'全唐诗/poet.song.121000.json','["絕頂無人處，融會亦非難。", "獨步依無住，圓心豈往還。", "深深妙在無言說，莫教閑指動風幡。", "大事徹頭須進步，白雲千里故鄉關。"]'),
('3462e936-a9d0-4c70-92de-a58f062a1df3','睹弟子作頌題窗乃續韻警之  其一','釋印肅','宋','宋诗','song-poetry','','[]','饒舌刀，刀不透，臨窗一語更離披。',32,'全唐诗/poet.song.121000.json','["饒舌刀，刀不透，臨窗一語更離披。", "儂家自有同風事，千里無來却肯伊。"]'),
('db727797-43e6-41ff-8064-7a86d23faf54','睹弟子作頌題窗乃續韻警之  其二','釋印肅','宋','宋诗','song-poetry','','[]','石人擊鼓木人吹，露柱親聞腦搭披。',32,'全唐诗/poet.song.121000.json','["石人擊鼓木人吹，露柱親聞腦搭披。", "如是圓音無用處，閻公未肯便饒伊。"]'),
('27af2406-ee99-431c-9072-268c0ed37f49','睹弟子作頌題窗乃續韻警之  其三','釋印肅','宋','宋诗','song-poetry','','[]','鼻孔遼天是阿誰，權將雲霧作衣披。',32,'全唐诗/poet.song.121000.json','["鼻孔遼天是阿誰，權將雲霧作衣披。", "迷悟本無唯一性，你全是我我無伊。"]'),
('582ceac2-2432-476e-9ed4-7232034d9ffb','睹弟子作頌題窗乃續韻警之  其四','釋印肅','宋','宋诗','song-poetry','','[]','普菴三頌自連拈，寄與提綱本手鉗。',32,'全唐诗/poet.song.121000.json','["普菴三頌自連拈，寄與提綱本手鉗。", "爐鞴穩時無鈍鐵，何妨矢上更加尖。"]'),
('58ca13e8-cc33-4a1a-8cf9-9b6b9e3320ef','四字書窗以印實相  其一','釋印肅','宋','宋诗','song-poetry','','[]','得正無非離一安，印空圓足寶瀰漫。',32,'全唐诗/poet.song.121000.json','["得正無非離一安，印空圓足寶瀰漫。", "天魔外道從何有，體若虛空世豈干。"]'),
('bdafb7c1-dc7b-4ed5-8c76-36b52844d8c1','四字書窗以印實相  其二','釋印肅','宋','宋诗','song-poetry','','[]','佳乘兩口草標頭，共見同看水牯牛。',32,'全唐诗/poet.song.121000.json','["佳乘兩口草標頭，共見同看水牯牛。", "昨夜牧人無被蓋，今朝猶笑道無求。"]'),
('ac6fddb4-419a-4059-b757-b2e4afddbe26','四字書窗以印實相  其三','釋印肅','宋','宋诗','song-poetry','','[]','實離貫穿理不俱，一人直下體同渠。',32,'全唐诗/poet.song.121000.json','["實離貫穿理不俱，一人直下體同渠。", "久停頑坐邪思起，返謗如來正覺虛。"]'),
('a02f2b05-62db-4fd3-b4b7-9f84a2645da2','四字書窗以印實相  其四','釋印肅','宋','宋诗','song-poetry','','[]','田頭十字路堂堂，鉗口收心便廝當。',32,'全唐诗/poet.song.121000.json','["田頭十字路堂堂，鉗口收心便廝當。", "領得摩尼真寶藏，却來警夢表提綱。"]'),
('3580aada-85ae-42e0-8949-2ae76edf151c','頌  其一','釋印肅','宋','宋诗','song-poetry','','[]','一輪心月耀昏衢，夢幻吞侵誰得知。',32,'全唐诗/poet.song.121000.json','["一輪心月耀昏衢，夢幻吞侵誰得知。", "幸遇知音重爲舉，息心回念理元輝。"]'),
('c6e32e4b-81dd-4291-ad28-1bdd17f4a04b','頌  其二','釋印肅','宋','宋诗','song-poetry','','[]','一句當天正信希，欲談詞喪懶投機。',32,'全唐诗/poet.song.121000.json','["一句當天正信希，欲談詞喪懶投機。", "高峰既遠休尋訪，不惜眉毛爲發揮。"]'),
('d4671ab8-449e-4db8-beb1-934378b0bffe','頌  其三','釋印肅','宋','宋诗','song-poetry','','[]','一身清浄本無瑕，了了歸家勝出家。',32,'全唐诗/poet.song.121000.json','["一身清浄本無瑕，了了歸家勝出家。", "紅葉舞風須早覺，莫將有限逐虛華。"]'),
('7034f662-a9dc-415f-a72f-4dc43ac0ac99','頌  其四','釋印肅','宋','宋诗','song-poetry','','[]','一心圓持種種心，信心諸境絕追尋。',32,'全唐诗/poet.song.121000.json','["一心圓持種種心，信心諸境絕追尋。", "此中無分應難到，便好回光免陸沉。"]'),
('500f3878-098e-4983-b03a-e0ad5bd0bf53','頌斷觜缾','釋印肅','宋','宋诗','song-poetry','','[]','心法無斷滅，踢倒一浄缾。',48,'全唐诗/poet.song.121000.json','["心法無斷滅，踢倒一浄缾。", "華林不奈何，不脫聲色名。", "真如俱是戲，心境一等平。", "不落有無用，三昧本空清。"]'),
('37d650e7-aca5-4b9c-8352-17fab5a65f6e','重陽日頌','釋印肅','宋','宋诗','song-poetry','','[]','去歲逢重九，風流主得賓。',48,'全唐诗/poet.song.121000.json','["去歲逢重九，風流主得賓。", "黄花談般若，白法樂天真。", "今夕當良會，高峰沒四鄰。", "孤筇挑日月，何道不通津。"]'),
('3fcbf8e9-6ac0-4621-9339-2011bae047b2','百丈先令慶上座禮拜求頌','釋印肅','宋','宋诗','song-poetry','','[]','西川慶上人，本來沒弟兄。',44,'全唐诗/poet.song.121000.json','["西川慶上人，本來沒弟兄。", "須知自性如空體，水月之中未解真。", "個事不傳聲色句，元來心法獨靈明。"]'),
('bd9169b3-757c-436e-b16e-5e76f1f85e16','送米與百丈頌','釋印肅','宋','宋诗','song-poetry','','[]','百丈孤雲入道林，真如不動意難尋。',48,'全唐诗/poet.song.121000.json','["百丈孤雲入道林，真如不動意難尋。", "道人相見非來往，語默全彰亙古今。", "近日廬陵親得價，一時分付老婆心。"]'),
('d8158f8d-3461-4e18-a53e-7d843474a3e2','行者妙曉求頌','釋印肅','宋','宋诗','song-poetry','','[]','頭頭相應人希會，物物皆真體不殊。',64,'全唐诗/poet.song.121000.json','["頭頭相應人希會，物物皆真體不殊。", "但辦肯心終不賺，情忘想盡入無餘。", "自是出家無眼目，只言苦行落空虛。", "甘贄在俗猶通理，妙曉無求自得珠。"]'),
('731bf0c5-171b-433b-b3b1-18399e00b2b7','紹椿行者求頌','釋印肅','宋','宋诗','song-poetry','','[]','假使八千五百歲，紹椿松鶴未爲奇。',64,'全唐诗/poet.song.121000.json','["假使八千五百歲，紹椿松鶴未爲奇。", "不若紹明光不變，此中實應出家時。", "念道何憂衣食事，千光影裏聽鶯啼。", "聞聲一囀渾消息，滿目蓮花不見枝。"]'),
('ee2514d9-0f12-420e-a244-3e7824dc14c0','陳達獻菊花求頌','釋印肅','宋','宋诗','song-poetry','','[]','滿地風光未足奇，霜前秋後吐金枝。',64,'全唐诗/poet.song.121000.json','["滿地風光未足奇，霜前秋後吐金枝。", "靈山親舉唯迦葉，今日陳來眾共知。", "不獨陶生時節用，轉爲華藏供阿彌。", "閒見定歸依彼岸，方知此日獻花時。"]'),
('98c4c87a-38b7-488d-8544-7e328cdef5cb','行住坐卧三十二頌  其一','釋印肅','宋','宋诗','song-poetry','','[]','普目不拘開合眼，意光何必待天明。',32,'全唐诗/poet.song.121000.json','["普目不拘開合眼，意光何必待天明。", "眾人未起我周布，行益資他腹自膨。"]'),
('b483aea1-21d9-48ec-8507-47bd9b596f65','行住坐卧三十二頌  其二','釋印肅','宋','宋诗','song-poetry','','[]','瀾渾湯水熟淘沙，不著油鹽醬醋茶。',32,'全唐诗/poet.song.121000.json','["瀾渾湯水熟淘沙，不著油鹽醬醋茶。", "饑渴隨時餐少許，只思因甚悟桃花。"]'),
('0961a247-01f6-4832-848b-9a4488344037','行住坐卧三十二頌  其三','釋印肅','宋','宋诗','song-poetry','','[]','割愛辭親如是行，豈求衣食及爲僧。',32,'全唐诗/poet.song.121000.json','["割愛辭親如是行，豈求衣食及爲僧。", "步步澄輝無別想，卓然獨立妙明生。"]'),
