('feb0e32e-cc39-470d-8775-97a0c6b34361','頌古九十八首  其四九','釋印肅','宋','宋诗','song-poetry','','[]','踢一踢時吹一吹，金毛師子現全威。',32,'全唐诗/poet.song.121000.json','["踢一踢時吹一吹，金毛師子現全威。", "趙州用處形言絕，爭奈迷頭不肯歸。"]'),
('d447deaa-425e-4c0d-b07f-c4a00bf1cfbf','頌古九十八首  其五○','釋印肅','宋','宋诗','song-poetry','','[]','門外君子至，一切人不會。',42,'全唐诗/poet.song.121000.json','["門外君子至，一切人不會。", "打這閑家具，甘贄與南泉。", "大地扶不起，爲甚扶不起，果報還如是。"]'),
('82c04249-117d-456d-beb4-3d4ecca73079','頌古九十八首  其五一','釋印肅','宋','宋诗','song-poetry','','[]','東西南北，通徹交過。',40,'全唐诗/poet.song.121000.json','["東西南北，通徹交過。", "悟者清凉，迷者大禍。", "隨流入流，法真不墮。", "若未全提，誰敢擔荷。"]'),
('43e06b5f-8d37-4dc6-81bb-765065459620','頌古九十八首  其五二','釋印肅','宋','宋诗','song-poetry','','[]','循水尋流不見源，逢人相問豈堪言。',32,'全唐诗/poet.song.121000.json','["循水尋流不見源，逢人相問豈堪言。", "知君背覺勞生解，謾語皆真意普賢。"]'),
('18d02f49-a406-4653-a44c-f84e9cbbd6ed','頌古九十八首  其五三','釋印肅','宋','宋诗','song-poetry','','[]','等閑平地掃塵埃，須還知有肯相陪。',32,'全唐诗/poet.song.121000.json','["等閑平地掃塵埃，須還知有肯相陪。", "悲風皓月猿啼急，窮子離家甚日回。"]'),
('b8f30d1e-5fe0-406f-82ba-598e47932b1d','頌古九十八首  其五四','釋印肅','宋','宋诗','song-poetry','','[]','關南老婆橫木劍，不露鋒鋩大靈驗。',32,'全唐诗/poet.song.121000.json','["關南老婆橫木劍，不露鋒鋩大靈驗。", "擲下威光絕見聞，豐城獨卓無餘欠。"]'),
('1eb116a1-d7a3-41af-804f-1ab68cd7cc63','頌古九十八首  其五五','釋印肅','宋','宋诗','song-poetry','','[]','標宗立法大瞞人，意氣彌陀局局親。',32,'全唐诗/poet.song.121000.json','["標宗立法大瞞人，意氣彌陀局局親。", "黑白不分難下手，放過一著大驚神。"]'),
('ea5550a1-fc7a-4e99-bda6-3403a3797608','頌古九十八首  其五六','釋印肅','宋','宋诗','song-poetry','','[]','心藏智寶少知音，全機付與水龍吟。',32,'全唐诗/poet.song.121000.json','["心藏智寶少知音，全機付與水龍吟。", "忽然撞著無相似，誰解光和活死人。"]'),
('0bee8beb-0f6b-4edd-8c4a-7fc0ade074cf','頌古九十八首  其五七','釋印肅','宋','宋诗','song-poetry','','[]','三聖戴角虎，德山獨眼龍。',48,'全唐诗/poet.song.121000.json','["三聖戴角虎，德山獨眼龍。", "未展機先合，非言意已通。", "風雲融萬象，笑哭是誰同。", "死中若不活，爭免被他籠。"]'),
('967c06a8-0bd5-4ab9-9409-67320f6ac560','頌古九十八首  其五八','釋印肅','宋','宋诗','song-poetry','','[]','察明表重驗虛無，不久堪爲唱導師。',32,'全唐诗/poet.song.121000.json','["察明表重驗虛無，不久堪爲唱導師。", "不覺驚動生滅相，臨時撮略顯精粗。"]'),
('63b9cc38-6827-45f7-bccc-f2f3fded6bff','頌古九十八首  其五九','釋印肅','宋','宋诗','song-poetry','','[]','雲無蹤兮雨無跡，事理綿綿有何極。',32,'全唐诗/poet.song.121000.json','["雲無蹤兮雨無跡，事理綿綿有何極。", "賣金須是買金人，這裏若真不相識。"]'),
('d93b714e-39fa-441a-a1bb-ae556f285e01','頌古九十八首  其六○','釋印肅','宋','宋诗','song-poetry','','[]','見道不生機，生機不見道。',48,'全唐诗/poet.song.121000.json','["見道不生機，生機不見道。", "青峰年年青，白水常浩浩。", "生熟路不通，迷悟俱不到。", "青白未萌前，樂普大深奧。"]'),
('90e94920-74e0-40d4-a460-d854f6e4c6ae','頌古九十八首  其六一','釋印肅','宋','宋诗','song-poetry','','[]','覿面相呈也大奇，更無分別與遲疑。',48,'全唐诗/poet.song.121000.json','["覿面相呈也大奇，更無分別與遲疑。", "自從收得非離合，豈可虛明放過伊。", "精金百鍊方爲貴，脫體靈明絕見知。"]'),
('89995657-492d-4e84-97fd-31c48afe57a0','頌古九十八首  其六二','釋印肅','宋','宋诗','song-poetry','','[]','妙指閑柴意馬師，失之千里費工夫。',32,'全唐诗/poet.song.121000.json','["妙指閑柴意馬師，失之千里費工夫。", "佛法不是這道理，拙用金毛作野狐。"]'),
('7f8f1223-cf9c-4e98-a126-1382a17c5205','頌古九十八首  其六三','釋印肅','宋','宋诗','song-poetry','','[]','口說難窮意普通，世間希有義和同。',32,'全唐诗/poet.song.121000.json','["口說難窮意普通，世間希有義和同。", "三春萬卉皆含笑，裝點繁花只一風。"]'),
('1b786ae0-eb93-46ca-ad9a-f76d4b56d609','頌古九十八首  其六四','釋印肅','宋','宋诗','song-poetry','','[]','提輪放線知深淺，把火燒山預辨宜。',32,'全唐诗/poet.song.121000.json','["提輪放線知深淺，把火燒山預辨宜。", "莫道逢場閑作戲，直須對病設良醫。"]'),
('f4fbb122-b269-4617-8a72-8b047ff043eb','頌古九十八首  其六五','釋印肅','宋','宋诗','song-poetry','','[]','孤舟不繫弄華亭，無限風光意氣清。',32,'全唐诗/poet.song.121000.json','["孤舟不繫弄華亭，無限風光意氣清。", "善會不干於耳目，豈容聲色付元靈。"]'),
('cdb08144-8e07-42ec-b993-c944f3434ca9','頌古九十八首  其六六','釋印肅','宋','宋诗','song-poetry','','[]','沒眼休談見藥山，免將明暗警盲參。',48,'全唐诗/poet.song.121000.json','["沒眼休談見藥山，免將明暗警盲參。", "特牛生子猶爲易，石女生兒豈似凡。", "孤明獨朗光無二，只恐癡猿攪碧潭。"]'),
('785230c6-7cfc-45f8-a421-41f0db80dea7','頌古九十八首  其六七','釋印肅','宋','宋诗','song-poetry','','[]','信地無閑處，知心用不非。',48,'全唐诗/poet.song.121000.json','["信地無閑處，知心用不非。", "微塵佛國土，妙在一毫釐。", "應當如是見，所說但隨宜。", "古錐無做作，謾把布毛吹。"]'),
('1ed6953f-3386-496f-8026-54f571a9b2ca','頌古九十八首  其六八','釋印肅','宋','宋诗','song-poetry','','[]','青天白日常相應，眼明方曉獼猴鏡。',32,'全唐诗/poet.song.121000.json','["青天白日常相應，眼明方曉獼猴鏡。", "自從曠劫不揩磨，知音謾舉無生令。"]'),
('a4b8ad05-2783-4981-86dc-6f8571c566fe','頌古九十八首  其六九','釋印肅','宋','宋诗','song-poetry','','[]','難信難聞獨眼龍，布雲施雨覓無蹤。',32,'全唐诗/poet.song.121000.json','["難信難聞獨眼龍，布雲施雨覓無蹤。", "却被普賢穿却鼻，如今眾信永無窮。"]'),
('e4eaf35c-2473-4781-a00e-bfe4432adce8','頌古九十八首  其七○','釋印肅','宋','宋诗','song-poetry','','[]','萬里草不生，三昧號無諍。',48,'全唐诗/poet.song.121000.json','["萬里草不生，三昧號無諍。", "夢游觀玉境，畢竟是誰行。", "在處曼曼地，只道無兩般。", "法門非出入，學者莫顢頇。"]'),
('bca7a007-a629-4546-8160-b1c822741bb0','頌古九十八首  其七一','釋印肅','宋','宋诗','song-poetry','','[]','带識髑髏撥死屍，箇中許道實難爲。',32,'全唐诗/poet.song.121000.json','["带識髑髏撥死屍，箇中許道實難爲。", "任渠碎我骨消散，終須不賺釋迦兒。"]'),
('cdd69b79-bc1e-45a3-a9df-7d6e6add49a0','頌古九十八首  其七二','釋印肅','宋','宋诗','song-poetry','','[]','令導禪和翠微峰，鐵壁銅牆路不同。',32,'全唐诗/poet.song.121000.json','["令導禪和翠微峰，鐵壁銅牆路不同。", "遥指雙林是歸處，至今猶尚鬼儱通。"]'),
('f23c7a47-c2cf-47b9-99d6-9409ef286597','頌古九十八首  其七三','釋印肅','宋','宋诗','song-poetry','','[]','古人投子續宗枝，相逢作者便呈機。',32,'全唐诗/poet.song.121000.json','["古人投子續宗枝，相逢作者便呈機。", "含光知有菴中主，提起油瓶應不疑。"]'),
('83b93674-7676-42bd-8c3e-b6da75cdd5f8','頌古九十八首  其七四','釋印肅','宋','宋诗','song-poetry','','[]','道人到處，全示真如。',20,'全唐诗/poet.song.121000.json','["道人到處，全示真如。", "若求言句，未免區區。"]'),
('0212dc0d-2527-42da-a876-5a1ecf85a4c2','頌古九十八首  其七五','釋印肅','宋','宋诗','song-poetry','','[]','探宗勘辨要當人，劫火燄中摝眼睛。',32,'全唐诗/poet.song.121000.json','["探宗勘辨要當人，劫火燄中摝眼睛。", "漸源頓入洪波裏，直至如今不見形。"]'),
('ab69b638-d313-4311-a8a7-0ab2cfbf3d87','頌古九十八首  其七六','釋印肅','宋','宋诗','song-poetry','','[]','洞山活計未全包，太老鉆龜罕辨爻。',32,'全唐诗/poet.song.121000.json','["洞山活計未全包，太老鉆龜罕辨爻。", "有物先天非相貌，豈干動用色相交。"]'),
('ae91c92a-db8e-4c7c-8511-9c6561138306','頌古九十八首  其七七','釋印肅','宋','宋诗','song-poetry','','[]','不識是真識有心，識心徧處不求人。',32,'全唐诗/poet.song.121000.json','["不識是真識有心，識心徧處不求人。", "江陵米滿元無價，師子全威畫不成。"]'),
('8d71dddb-9a1e-4571-8199-68b3932fcf6b','頌古九十八首  其七八','釋印肅','宋','宋诗','song-poetry','','[]','家不破兮人不亡，設機不應轉郎當。',32,'全唐诗/poet.song.121000.json','["家不破兮人不亡，設機不應轉郎當。", "龜毛拂子呵呵笑，六月炎天好大霜。"]'),
('7ecff8ec-adf1-4307-8b1b-1e7d5999b81d','頌古九十八首  其七九','釋印肅','宋','宋诗','song-poetry','','[]','釋梵天帝，寶冠履地。',40,'全唐诗/poet.song.121000.json','["釋梵天帝，寶冠履地。", "不誦華嚴，佛不富貴。", "離四句非，絕百非是。", "絕百非非，離四句易。"]'),
('ec8971e4-0c02-4761-947c-0544b039059b','頌古九十八首  其八○','釋印肅','宋','宋诗','song-poetry','','[]','一撥眉毛露眼睛，只傷底許沒瞳人。',32,'全唐诗/poet.song.122000.json','["一撥眉毛露眼睛，只傷底許沒瞳人。", "燈籠開口呵呵笑，衲僧和夢蹈車輪。"]'),
('9ef2f566-5465-4d14-9488-ebb9aaaa321a','頌古九十八首  其八一','釋印肅','宋','宋诗','song-poetry','','[]','古今學道與參禪，未諳眼耳妙言詮。',32,'全唐诗/poet.song.122000.json','["古今學道與參禪，未諳眼耳妙言詮。", "一粒玄沙無住本，時時興販海南船。"]'),
('d00009d2-5c60-4823-ae0e-5d90914453fd','頌古九十八首  其八二','釋印肅','宋','宋诗','song-poetry','','[]','龍濟興雲雨徧施，聖凡不落與誰齊。',32,'全唐诗/poet.song.122000.json','["龍濟興雲雨徧施，聖凡不落與誰齊。", "能持地藏無空印，具足圓方始不疑。"]'),
('4013aac3-397c-42c6-a1b3-0b896434862f','頌古九十八首  其八三','釋印肅','宋','宋诗','song-poetry','','[]','鏡含世界幾千春，非相非形假立名。',32,'全唐诗/poet.song.122000.json','["鏡含世界幾千春，非相非形假立名。", "汩沒未嘗離鏡體，憐生誰合飲光人。"]'),
('52e69839-92b1-40bc-876a-c213be2c0e3a','頌古九十八首  其八四','釋印肅','宋','宋诗','song-poetry','','[]','大秤秤不起，小斗量不盡。',24,'全唐诗/poet.song.122000.json','["大秤秤不起，小斗量不盡。", "無量劫即今，無不是心印。"]'),
('6d8046f4-1b19-4bd4-b05e-e0609e694827','頌古九十八首  其八五','釋印肅','宋','宋诗','song-poetry','','[]','船子寥寥載不空，幾回明月弄清風。',32,'全唐诗/poet.song.122000.json','["船子寥寥載不空，幾回明月弄清風。", "呈橈舞棹無他事，只欲教人解六通。"]'),
('2c411907-8d39-4b0f-87eb-d5a28e7665dc','頌古九十八首  其八六','釋印肅','宋','宋诗','song-poetry','','[]','何處無雲不是門，藏鋒不露理難論。',32,'全唐诗/poet.song.122000.json','["何處無雲不是門，藏鋒不露理難論。", "雪峰未盡玄沙意，惹得村人村又村。"]'),
('afcdadc8-ee38-440c-8c2c-6b46835e3fb9','頌古九十八首  其八七','釋印肅','宋','宋诗','song-poetry','','[]','似水煎茶待故人，知音喫了笑忻忻。',32,'全唐诗/poet.song.122000.json','["似水煎茶待故人，知音喫了笑忻忻。", "茶水本來無一說，揚眉早是自瞞心。"]'),
('65d5a105-50ec-4a30-912c-133a928006f7','頌古九十八首  其八八','釋印肅','宋','宋诗','song-poetry','','[]','拈古談今我尚無，木奴草女辨工夫。',32,'全唐诗/poet.song.122000.json','["拈古談今我尚無，木奴草女辨工夫。", "草木恰知非外物，含靈那信自毗盧。"]'),
('c1e851d6-23b4-47ad-9e8c-a3c5993558a2','頌古九十八首  其八九','釋印肅','宋','宋诗','song-poetry','','[]','飛空著地情依識，大地山河情識磨。',32,'全唐诗/poet.song.122000.json','["飛空著地情依識，大地山河情識磨。", "色空明暗無相似，挑起蛇時會也麽。"]'),
('4f000099-7268-4c78-8f3b-af8a924895c0','頌古九十八首  其九○','釋印肅','宋','宋诗','song-poetry','','[]','立亡坐脫不爲奇，石霜遷化少人知。',32,'全唐诗/poet.song.122000.json','["立亡坐脫不爲奇，石霜遷化少人知。", "九峰師子連天吼，剎那驚殺野狐狸。"]'),
('6ce588ef-34cd-4508-bea0-4019f0f9b978','頌古九十八首  其九一','釋印肅','宋','宋诗','song-poetry','','[]','打開兜率露王宮，摩耶夫人沒老去。',32,'全唐诗/poet.song.122000.json','["打開兜率露王宮，摩耶夫人沒老去。", "浄飯國王生太子，字字言言說脫空。"]'),
('ffe3a3b5-89a8-4f61-a5d6-0cb6860aaeff','頌古九十八首  其九二','釋印肅','宋','宋诗','song-poetry','','[]','玄沙大用，雪峰三弄。',20,'全唐诗/poet.song.122000.json','["玄沙大用，雪峰三弄。", "大地山河，六徧震動。"]'),
('11ec58bc-8bd8-4c4f-bba6-8d2c9da0c90e','頌古九十八首  其九三','釋印肅','宋','宋诗','song-poetry','','[]','日裏不可道人，夜裏不可說鬼。',28,'全唐诗/poet.song.122000.json','["日裏不可道人，夜裏不可說鬼。", "無量劫來成道，一時都在這裏。"]'),
('0a09bf5d-8e0c-4dde-a739-d15b5a8e7094','頌古九十八首  其九四','釋印肅','宋','宋诗','song-poetry','','[]','三脚驢子弄蹄行，只欲途中拶後生。',32,'全唐诗/poet.song.122000.json','["三脚驢子弄蹄行，只欲途中拶後生。", "一片丹霞塵不染，包藏萬有豈稱能。"]'),
('6029c4e2-10dc-4f2f-b59d-e6703ed44973','頌古九十八首  其九五','釋印肅','宋','宋诗','song-poetry','','[]','魚在岸時活不久，人落深淵當下亡。',32,'全唐诗/poet.song.122000.json','["魚在岸時活不久，人落深淵當下亡。", "川陸誰知同一性，恰如地獄與天堂。"]'),
('3f250447-d2a8-4d3b-ae50-ca7af460b23f','頌古九十八首  其九六','釋印肅','宋','宋诗','song-poetry','','[]','無相光中弄影人，形同異類性天真。',32,'全唐诗/poet.song.122000.json','["無相光中弄影人，形同異類性天真。", "披毛戴角冰和水，削髮披衣水合冰。"]'),
('1fe44d81-bafb-4637-a9e2-f4df63807b73','頌古九十八首  其九七','釋印肅','宋','宋诗','song-poetry','','[]','古人遺意不留言，婆子臺山著一邊。',32,'全唐诗/poet.song.122000.json','["古人遺意不留言，婆子臺山著一邊。", "識得臺山婆子了，趙州消息沒休年。"]'),
('9a34de68-b4f7-40bc-9bd6-f1532216a13c','頌古九十八首  其九八','釋印肅','宋','宋诗','song-poetry','','[]','趙州火急要人成，大眾渾無半眼窺。',32,'全唐诗/poet.song.122000.json','["趙州火急要人成，大眾渾無半眼窺。", "騎個金毛游物外，南泉滴滴意深深。"]'),
('eb41c489-b2d5-43c8-b2d9-55119844b71c','普菴家寶','釋印肅','宋','宋诗','song-poetry','','[]','普菴家寶，不著尋討。',240,'全唐诗/poet.song.122000.json','["普菴家寶，不著尋討。", "迷時不見，在處煩惱。", "悟時無相，如日杲杲。", "取舍不得，自然恰好。", "誰生誰病，誰死誰老。", "達人無證，凡夫顛倒。", "日西道晚，日東道早。", "有睛無眼，撞頭磕腦。", "扶籬摸壁，棄金抱草。", "機關木人，弄口叫好。", "線牽則動，索斷則倒。", "撒放閑處，如第爛藁。", "本自無形，被他作造。", "五彩妝來，安名立號。", "只欲瞞他，何曾自保。", "打鬧過日，全無倚靠。", "問他貴姓，口中便道。", "草木李張，適來方到。", "有甚急事，特來干冒。", "衣食不足，莫怪聒燥。", "人口不安，田園旱澇。", "賺埋公祖，移墳修造。", "被術人算，年月不好。", "朝山拜嶽，何處不到。"]'),
('7e40537b-488e-4c1b-add9-414d0e908806','從何使君父子遊墨池分韻得名字','李燾','宋','宋诗','song-poetry','','[]','蜀學擅天下，馬王先得名。',204,'全唐诗/poet.song.122000.json','["蜀學擅天下，馬王先得名。", "簧如巧言語，於道蓋小成。", "子雲最後出，振策思遐征。", "斯文大一統，欻使聖域清。", "富貴盡在我，紱冕非所榮。", "旁皇天祿閣，聊亦觀我生。", "懷哉不能歸，舊宅荒榛荆。", "寂寞竟誰顧，正路今莫行。", "使君蓬萊仙，弭節歸赤城。", "門無俗賓客，家有賢父兄。", "慨念此耆老，不登漢公卿。", "臨池一罇酒，尚友千載英。", "并呼嚴與李，月旦共細評。", "區區可無憾，彼重適我輕。", "朅來成都市，塵土污冠纓。", "古人不可見，見此眼自明。", "請爲懷古詩，玉振而金聲。"]'),
('864c17ec-9fe3-416a-a2ed-0749b902e314','題龍鵠山房','李燾','宋','宋诗','song-poetry','','[]','已作清時鳥倦飛，杜鵑更勸阿誰歸。',32,'全唐诗/poet.song.122000.json','["已作清時鳥倦飛，杜鵑更勸阿誰歸。", "似嫌住處猶城郭，不解携家隱翠微。"]'),
('9f520bd9-52c2-463c-a585-f904420491ef','客懷  其一','李燾','宋','宋诗','song-poetry','','[]','寂寞三秋節，淒凉萬里風。',48,'全唐诗/poet.song.122000.json','["寂寞三秋節，淒凉萬里風。", "關河盡形勝，人物幾英雄。", "秦葉隨流水，周禾滿故宮。", "此心懸象闕，夢繞浙西東。"]'),
('2a0225c2-04e1-49cd-b713-3a11db691f3b','客懷  其二','李燾','宋','宋诗','song-poetry','','[]','久客厭塵土，幽居懷翠微。',48,'全唐诗/poet.song.122000.json','["久客厭塵土，幽居懷翠微。", "只餘清夜夢，長作故山歸。", "菊已開三逕，松應長十圍。", "晨鐘忽驚覺，猶有露沾衣。"]'),
('db758500-fa62-4508-aebb-9933d16298d2','客懷  其三','李燾','宋','宋诗','song-poetry','','[]','壯矣府中縣，索如城外村。',48,'全唐诗/poet.song.122000.json','["壯矣府中縣，索如城外村。", "墨池今掃迹，石筍舊餘根。", "風急漢絃斷，雨多秦鏡昏。", "新秋一懷古，情緒若爲論。"]'),
('9df83a63-28b6-43de-a4f8-eb65a53deec2','客懷  其四','李燾','宋','宋诗','song-poetry','','[]','雨意忽如此，客愁將奈何。',48,'全唐诗/poet.song.122000.json','["雨意忽如此，客愁將奈何。", "出門誰可詣，掩卷獨高歌。", "塵世兔三穴，古人蓬一窠。", "區區奚足道，默默幸無它。"]'),
('30c1040a-53c3-4c6f-9b6d-4bd58b0aa6de','客懷  其五','李燾','宋','宋诗','song-poetry','','[]','長憶在家好，已知從仕難。',48,'全唐诗/poet.song.122000.json','["長憶在家好，已知從仕難。", "紛紛猶嚇鼠，悄悄政棲鸞。", "忘意躡高位，敢言卑小官。", "世途真甚隘，懷抱要須寬。"]'),
('e9018226-161f-4c00-8b7d-31e40458b36e','靈雲巖','李燾','宋','宋诗','song-poetry','','[]','路轉層岡十里餘，武陵傳者亦難如。',64,'全唐诗/poet.song.122000.json','["路轉層岡十里餘，武陵傳者亦難如。", "昔年煉藥仙人室，今日餐霞道士居。", "洞外蟠花開錦繡，巖前石溜漱瓊琚。", "猗歟靈氣爲時雨，可惜圖經闕不書。"]'),
('f67a50d1-0586-4017-a87e-a248d14ec59a','三月二十日出郊泛舟西津得予字','李燾','宋','宋诗','song-poetry','','[]','春日行郊坰，南風初唱予。',48,'全唐诗/poet.song.122000.json','["春日行郊坰，南風初唱予。", "相携出城郭，著意買江湖。", "句好從兒覓，杯乾任客呼。", "長年足詩酒，此外復何須。"]'),
('04067d69-dc41-4699-b62f-de25cb7374de','信相院水月亭','李燾','宋','宋诗','song-poetry','','[]','水中之月不可取，收攬結成湖上亭。',64,'全唐诗/poet.song.122000.json','["水中之月不可取，收攬結成湖上亭。", "天光沉沉射虛白，夜色耿耿含空青。", "朅來窮冬所見異，但有破塊黏枯萍。", "吾心皎潔竟何似，本自無物誰當銘。"]'),
('1b893d6f-0f23-449c-8852-8f85de7be90a','十月過昭覺庭梅蕭然已動人意因作二十八字','李燾','宋','宋诗','song-poetry','','[]','厭逐遊人藥市行，暫來心迹喜雙清。',32,'全唐诗/poet.song.122000.json','["厭逐遊人藥市行，暫來心迹喜雙清。", "疏風細雨荒庭菊，便覺梅花暗有情。"]'),
('677dd7c6-eeef-4fc6-bed3-e0429d42b025','觀施氏芍藥呈同遊者','李燾','宋','宋诗','song-poetry','','[]','怪底吹殘萬點紅，餘妍都在此花中。',64,'全唐诗/poet.song.122000.json','["怪底吹殘萬點紅，餘妍都在此花中。", "攀枝未許風流盡，振袂還知結習空。", "杳杳人誰贈南園，菲菲身恐墮仙宮。", "乞將新雨酬佳麗，始信青春不負公。"]'),
('36c01a1a-5f41-420f-90be-a175a83232a9','成都施氏園海棠方盛時覓酒徑醉二月九日','李燾','宋','宋诗','song-poetry','','[]','染根著色謝天公，破睡猶禁一再風。',32,'全唐诗/poet.song.122000.json','["染根著色謝天公，破睡猶禁一再風。", "爲此徑須浮大白，老夫元自愛深紅。"]'),
('add4e310-626f-479b-b2b5-064d545f89ac','游蔡山','李燾','宋','宋诗','song-poetry','','[]','巖巒最高頂，雲氣時蔚薈。',24,'全唐诗/poet.song.122000.json','["巖巒最高頂，雲氣時蔚薈。", "彷彿羣仙宅，宮闕曜珠貝。"]'),
('be61a7c1-2164-41b5-9d2c-bc471ea973a3','長生觀','李燾','宋','宋诗','song-poetry','','[]','成家得將軍，如越大夫蠡。',24,'全唐诗/poet.song.122000.json','["成家得將軍，如越大夫蠡。", "功成拂衣去，智囊未叩底。"]'),
('fdd797cd-4123-4af0-87e2-c285e481afbd','望川亭','李燾','宋','宋诗','song-poetry','','[]','潼川遶郭多名寺，都在少陵詩句中。',32,'全唐诗/poet.song.122000.json','["潼川遶郭多名寺，都在少陵詩句中。", "西上飛亭更奇絕，水光山色兩無窮。"]'),
('1489a6e9-6672-41b9-a835-be3581ed64c5','岑公洞','李燾','宋','宋诗','song-poetry','','[]','隋邦危亂誰得免，虛鑒真人願獨行。',32,'全唐诗/poet.song.122000.json','["隋邦危亂誰得免，虛鑒真人願獨行。", "道骨仙風今可想，幽棲巖洞及高明。"]'),
('808ed3b4-c765-494f-b5a8-b4cfd4ec858b','昇元寺  其一','李燾','宋','宋诗','song-poetry','','[]','看盡庵前手種松，草堂聊復少從容。',32,'全唐诗/poet.song.122000.json','["看盡庵前手種松，草堂聊復少從容。", "令人却憶騎驢老，悔不終身作卧龍。"]'),
('7f6e9ce8-3ffd-4357-a124-57e730663b66','昇元寺  其二','李燾','宋','宋诗','song-poetry','','[]','昇元古寺寶靈珠，照影東西與眾殊。',32,'全唐诗/poet.song.122000.json','["昇元古寺寶靈珠，照影東西與眾殊。", "本爲仁皇賁潛府，豈知今日鎮留都。"]'),
('3406a169-6b75-4dc1-9cee-73423dc2a2e9','擁翠樓','李燾','宋','宋诗','song-poetry','','[]','淳熙元年九月尾，菊未落英梅破蕊。',96,'全唐诗/poet.song.122000.json','["淳熙元年九月尾，菊未落英梅破蕊。", "從來兩美難必合，今忽得此一笑喜。", "人言地瘴物失時，進忌太蚤退苦遲。", "老夫亦豈不自覺，姑與飲酒仍賦詩。", "忍令芳草直爲艾，封植嘉樹寧少待。", "夕餐九華可無死，却期老歲於吾子。"]'),
('3e6c035c-da22-4f97-b3d2-8c4aaebd1164','洞庭','李燾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','鏡面千頃闊，修眉一带橫。',48,'全唐诗/poet.song.122000.json','["鏡面千頃闊，修眉一带橫。", "湖深有龍蟄，山靜少人行。", "似與真仙約，都無世俗情。", "鳥啼猿叫歇，軒樂有餘聲。"]'),
('f8cc47d5-d8e9-44f3-831a-f45b6a5995c0','制勝樓','李燾','宋','宋诗','song-poetry','','[]','畫省容臺記並遊，相思相望幾登樓。',64,'全唐诗/poet.song.122000.json','["畫省容臺記並遊，相思相望幾登樓。", "路長久歎音塵絕，事變還驚歲月流。", "合侍鈞天終雅奏，却穿巴峽看橫舟。", "欲酬嘉惠須新語，老覺枯腸不奈搜。"]'),
('e00d975b-fc94-41b3-9f72-17e71e1528bc','登金山','李燾','宋','宋诗','song-poetry','','[]','金山何處好，四顧不相連。',48,'全唐诗/poet.song.122000.json','["金山何處好，四顧不相連。", "窗迥前無地，波澄下有天。", "堂留三楚客，門泊五湖船。", "暝色關詩思，江籠兩岸烟。"]'),
('fb88f58a-c7f4-4504-b231-a8a516ed495f','龍鵠山','李燾','宋','宋诗','song-poetry','','[]','西山有佳人，慣踏山下路。',36,'全唐诗/poet.song.122000.json','["西山有佳人，慣踏山下路。", "晨吟澤畔風，午睡巖前雨。", "莫使兒輩覺，損我巖壑趣。"]'),
('ea6cab8c-a4e6-4907-bae7-7179c80074c2','鼎建金釜仙山靈泉古觀碑','李燾','宋','宋诗','song-poetry','','[]','臣閪獨步轉淦浪，□□□□□□陽。',64,'全唐诗/poet.song.122000.json','["臣閪獨步轉淦浪，□□□□□□陽。", "風生□□□□□，紫氣繽紛賽錦堂。", "欲頻了了載詩酒，總爲超□□□陰。", "幽勝若天香境萬，□舍興樂招掌愛。"]'),
('4acdf5e3-ecd0-4a11-bdf3-0446a66fa78f','句  其一','李燾','宋','宋诗','song-poetry','','[]','試上層樓高處望，十洲三島似蓬萊。',16,'全唐诗/poet.song.122000.json','["試上層樓高處望，十洲三島似蓬萊。"]'),
('d4142286-0ad2-4e11-95a5-dc3ce4236536','句  其二','李燾','宋','宋诗','song-poetry','','[]','瓦屋如案平，金仙閟光景。',12,'全唐诗/poet.song.122000.json','["瓦屋如案平，金仙閟光景。"]'),
('03b3b4e2-3165-439a-9022-2f1e20140f79','句  其三','李燾','宋','宋诗','song-poetry','','[]','斷碑唐日寺，遺像晉時僧。',12,'全唐诗/poet.song.122000.json','["斷碑唐日寺，遺像晉時僧。"]'),
('793869e0-02fa-46f5-ba94-cd45f3898381','句  其四','李燾','宋','宋诗','song-poetry','','[]','山遶一城藏幾寺，江連二水送孤舟。',16,'全唐诗/poet.song.122000.json','["山遶一城藏幾寺，江連二水送孤舟。"]'),
('78c5479e-4b4e-4da9-9793-dcd78891d5b0','句  其五','李燾','宋','宋诗','song-poetry','','[]','平蓋神仙院，武陽山水鄉。',12,'全唐诗/poet.song.122000.json','["平蓋神仙院，武陽山水鄉。"]'),
('1fad03c8-9e1e-41ba-855d-8c614aa7c7d7','句  其六','李燾','宋','宋诗','song-poetry','','[]','行亦自劾去。',6,'全唐诗/poet.song.122000.json','["行亦自劾去。"]'),
('2040cc51-af4c-46e7-accd-e4766e77686e','從沈文伯乞娑羅樹碑','芮燁','宋','宋诗','song-poetry','','[]','楚州淮陰娑羅樹，霜露榮悴今何如。',48,'全唐诗/poet.song.122000.json','["楚州淮陰娑羅樹，霜露榮悴今何如。", "能令草木死不朽，當時爲有北海書。", "荒碑雨侵澀苔蘚，尚想墨本傳東吳。"]'),
('a2ab7043-c7e4-4a4c-9442-98509a17cc60','題鶯花亭','芮燁','宋','宋诗','song-poetry','','[]','人言多技亦多窮，隨意文章要底工。',32,'全唐诗/poet.song.122000.json','["人言多技亦多窮，隨意文章要底工。", "淮海秦郎天下士，一生懷抱百憂中。"]'),
('2eed0056-ff5a-46d5-a1b8-26465b284c8b','羅浮寶積寺','芮燁','宋','宋诗','song-poetry','','[]','木落天寒山氣沈，年華客意共蕭森。',64,'全唐诗/poet.song.122000.json','["木落天寒山氣沈，年華客意共蕭森。", "偶于佳處發深省，其實宦遊非本心。", "紅日坐移鐘閣影，白雲閑度石樓陰。", "還家莫話神仙事，老不寬人雪滿簪。"]'),
('20500132-569c-492a-b4cc-283f339c8bdd','贈陳少微','芮燁','宋','宋诗','song-poetry','','[]','原思非病貧何患，回也雖貧樂有加。',32,'全唐诗/poet.song.122000.json','["原思非病貧何患，回也雖貧樂有加。", "歲晚與誰同此味，梅花深處是君家。"]'),
('868fb2e8-03a7-4370-8d29-c299f0d7a0d8','東林寺','芮燁','宋','宋诗','song-poetry','','[]','脩竹長林羅水車，梵王家近葛僊宮。',64,'全唐诗/poet.song.122000.json','["脩竹長林羅水車，梵王家近葛僊宮。", "耳聞清磬是非靜，心領菩提名利空。", "啖棗尚知前世事，拈花還遇上機翁。", "抽簪若得燒丹訣，莫負扶桑半夜紅。"]'),
('94395432-3380-4171-ab4a-ffdd34d952ee','句  其一','芮燁','宋','宋诗','song-poetry','','[]','今作塵埃奔走人。',8,'全唐诗/poet.song.122000.json','["今作塵埃奔走人。"]'),
('97bce683-1eb5-4f35-8cbf-ce26427e12ba','句  其二','芮燁','宋','宋诗','song-poetry','','[]','今日桐城王刺史，異時遺愛在吾州。',16,'全唐诗/poet.song.122000.json','["今日桐城王刺史，異時遺愛在吾州。"]'),
('796879ab-205e-4fd5-ac87-dece3e5d5384','句  其三','芮燁','宋','宋诗','song-poetry','','[]','寧令漢社稷，變作莽乾坤。',12,'全唐诗/poet.song.122000.json','["寧令漢社稷，變作莽乾坤。"]'),
('7b758ea2-eb8e-4ea3-831d-92b420262288','皇后閣春帖子','陸升之','宋','宋诗','song-poetry','','[]','內仗朝初退，朝曦滿翠屏。',24,'全唐诗/poet.song.122000.json','["內仗朝初退，朝曦滿翠屏。", "硯池渾不凍，端爲寫蘭亭。"]'),
('0567d567-19c6-4086-8ebe-bce61bcb16ab','臨終詩','傅得一','宋','宋诗','song-poetry','','[]','平生膽氣清高，抱道長樂逍遥。',28,'全唐诗/poet.song.122000.json','["平生膽氣清高，抱道長樂逍遥。", "天地陰陽反覆，雲收霧捲丹霄。"]'),
('934d06fc-31f9-4030-b357-c5d3e3d242e5','題徐熙牡丹圖','吳皇后','宋','宋诗','song-poetry','','[]','吉祥亭下萬年枝，看盡將開欲落時。',32,'全唐诗/poet.song.122000.json','["吉祥亭下萬年枝，看盡將開欲落時。", "却是雙紅有深意，故留春色緩人思。"]'),
('9e111347-0bc9-4e7e-9123-563cb2074fba','題徐熙芍藥','吳皇后','宋','宋诗','song-poetry','','[]','穠李夭桃掃地無，眼明驚見玉盤盂。',32,'全唐诗/poet.song.122000.json','["穠李夭桃掃地無，眼明驚見玉盤盂。", "揚州省識春風面，看盡群花總不如。"]'),
('2cb18498-f1a3-47a1-9766-c42c5262a47c','句','樊賓','宋','宋诗','song-poetry','','[]','恥見橫人欺楚約，忍聞稚子勸君行。',16,'全唐诗/poet.song.122000.json','["恥見橫人欺楚約，忍聞稚子勸君行。"]'),
('897a3950-acbe-49f5-9659-0168b924c875','點易亭','司馬伋','宋','宋诗','song-poetry','','[]','洞天占勝作新亭，曲檻危簷揖翠屏。',64,'全唐诗/poet.song.122000.json','["洞天占勝作新亭，曲檻危簷揖翠屏。", "四顧風烟入懷裏，一灣溪水抱沙汀。", "羽人不見論平昔，雙鶴猶存有典型。", "幸得官閑成吏隱，何妨續說舊羲經。"]'),
('6cbaf72b-43d9-44df-8f17-0d89d19f4bcc','送汪尚書大猷歸鄞  其一','司馬伋','宋','宋诗','song-poetry','','[]','憶昔銓衡地，爲郎得並遊。',48,'全唐诗/poet.song.122000.json','["憶昔銓衡地，爲郎得並遊。", "惟公合明陟，顧我分夷猶。", "功業行將遂，軒車去莫留。", "祠庭固誠請，帝眷益綢繆。"]'),
('4c52583a-6884-436b-ae1d-d6cbb6afe134','送汪尚書大猷歸鄞  其二','司馬伋','宋','宋诗','song-poetry','','[]','日者真奇中，春風畫鷁行。',48,'全唐诗/poet.song.122000.json','["日者真奇中，春風畫鷁行。", "東山須繼起，南浦獨傷情。", "越岸江山麗，都門祖道榮。", "里閭高卧際，趣詔逐追程。"]'),
('b53d9051-7818-4ccc-b90a-23b200020d07','三老堂','胡彥國','宋','宋诗','song-poetry','','[]','歷陽賓主昔多賢，三老風流二十年。',32,'全唐诗/poet.song.122000.json','["歷陽賓主昔多賢，三老風流二十年。", "獬豸冠中曾補衮，鳳凰池上迭擎天。"]'),
('e97744ec-d04e-4871-86ab-d7f3f894731a','山中雜詠  其一','許必勝','宋','宋诗','song-poetry','','[]','久病鮮塵事，溪山遂相安。',96,'全唐诗/poet.song.122000.json','["久病鮮塵事，溪山遂相安。", "欲知生息意，自樹庭中蘭。", "靜睹花葉榮，春風吹亦難。", "新禽弄佳吹，小水生微瀾。", "同在天地中，安能測其端。", "夜澄眾境寂，月小松聲寒。", "言念御風人，感茲清露漙。", "悲來心自微，凄然竟長嘆。"]'),
('c84082df-0a68-417b-ae66-994c37ceb016','山中雜詠  其二','許必勝','宋','宋诗','song-poetry','','[]','月至林木異，心空來遠聲。',60,'全唐诗/poet.song.122000.json','["月至林木異，心空來遠聲。", "草根幽響奏，小葉孤螢明。", "靜念既有在，久之無可名。", "輕雲自閑暇，坐久山風鳴。", "微雨偶然過，清心相向生。"]'),
('1680b28a-646f-4f36-a35d-a9dfc6488742','山中雜詠  其三','許必勝','宋','宋诗','song-poetry','','[]','鳥亂南山雲，日照南山綠。',84,'全唐诗/poet.song.122000.json','["鳥亂南山雲，日照南山綠。", "東風語流鶯，相吹還斷續。", "撫彼石上泉，平生自云足。", "浮榮不常御，迴薄無停矚。", "苟非女蘿枝，焉能事屈曲。", "峨峨高山松，漾漾深溪淥。", "持此雲外心，一謝西飛鵠。"]'),
('d50fdb45-0476-4ed0-afb9-a224c06bfb9a','山中雜詠  其四','許必勝','宋','宋诗','song-poetry','','[]','灼灼山半花，閑閑水中藻。',96,'全唐诗/poet.song.122000.json','["灼灼山半花，閑閑水中藻。", "苟無松柏心，飄零向誰道。", "蜉蝣炫衣裳，楚楚苦不保。", "野老惜春色，間籬薙青草。", "青草忽已繁，蘭蕙日已老。", "蘭蕙日已老，我心當奈何。", "人生貴適意，所樂豈在多。", "卓然負書翁，悠悠謝山阿。"]'),
('e240e35a-e8d1-40d4-a76a-c3faa105cc3a','憶舊游  其一','許必勝','宋','宋诗','song-poetry','','[]','歡遊成逝波，盛華落殘照。',132,'全唐诗/poet.song.122000.json','["歡遊成逝波，盛華落殘照。", "每憶清池遊，幽魂夜相弔。", "與君携手時，雲林正清妙。", "天空露光動，襟衫見高調。", "及來愁病侵，瘦骨冰稜峭。", "君如鏡中花，獨向春光笑。", "荒村酒味薄，沉憂何時療。", "日色不入夢，高星凍青耀。", "空枝吟霜風，永夜興悲嘯。", "嵯峨金張第，忽成野田燒。", "安得明月中，長見君年少。"]'),
('4b2ec7f7-c9ce-4d90-80e0-a337a3e23f88','憶舊游  其二','許必勝','宋','宋诗','song-poetry','','[]','孤桐飽秋風，響作霜天鴻。',108,'全唐诗/poet.song.122000.json','["孤桐飽秋風，響作霜天鴻。", "手翻九嶷色，下墮瀟湘中。", "誰言一寸路，不成西與東。", "誰言少年時，不成衰老翁。", "欲使膠漆意，通君山水衷。", "嘗恐金石奏，復爲鄭衛工。", "所悲百年內，徒然羨華嵩。", "華嵩有終極，愁淚終難窮。", "愁淚一入地，春風無碧叢。"]'),
('a0b0d03c-95e0-4fe8-b995-4d8270d2115e','舟行','許必勝','宋','宋诗','song-poetry','','[]','雨脚天東來，驚鳥烟中起。',108,'全唐诗/poet.song.122000.json','["雨脚天東來，驚鳥烟中起。", "須臾四山合，萬象空濛裏。", "孤行念遠村，見樹聯自喜。", "浪遊豈無因，遇山則知止。", "稜稜雲外峰，與我心終始。", "日暮宿田家，田歌正清美。", "何以途路心，歷亂如流水。", "始疑車馬上，未必見君子。", "行當弄輕舟，隨風問蘭芷。"]'),
('aeac1df9-8074-4182-8550-7a89be8ad840','除夕','許必勝','宋','宋诗','song-poetry','','[]','多病成懶疎，日月忽驅逐。',132,'全唐诗/poet.song.122000.json','["多病成懶疎，日月忽驅逐。", "家人厭陳迹，灑掃新我目。", "爭此須臾間，擾擾競多福。", "習氣變性情，不復生慚恧。", "幸有一樽酒，可以寄清穆。", "夜靜天四垂，星光就簷屋。", "燈燭忽空曠，琴書轉幽獨。", "休心薇蕨內，庶免營旨蓄。", "鳳凰鳴高岡，貽笑於雞鶩。", "得終歲寒心，尚愧庭前竹。", "去去天台山，幽蘭會當馥。"]'),
('36caa22a-37ea-4718-bf8e-e14b03c70896','春日作','許必勝','宋','宋诗','song-poetry','','[]','雨過驗庭樹，始知春氣還。',144,'全唐诗/poet.song.122000.json','["雨過驗庭樹，始知春氣還。", "造化不相限，隨意成斑斕。", "蒙蒙一寸枝，新故傷其間。", "四時遞相見，花葉了不閒。", "安能待頭白，然後凋朱顔。", "陽春久斷絕，夢想見弓彎。", "醉後發高唱，狂句請莫刪。", "不貴文字奇，貴使耳目頑。", "從來賢智出，不與庸俗關。", "性情通草木，羞辨魑魅奸。", "周道滿荆棘，歧路盈海寰。", "舉足何所蹈，歸去天台山。"]'),
('82306f3b-5317-4d4a-a41d-3070f5cf8771','苦雨','許必勝','宋','宋诗','song-poetry','','[]','積憂遂成陰，昏色遍蒼莽。',144,'全唐诗/poet.song.122000.json','["積憂遂成陰，昏色遍蒼莽。", "我醉憂已忘，天地當開朗。", "何以酒醒後，猶然在簷上。", "云是方春時，暗助草木長。", "凝陰而無陽，亦非善培養。", "豈因世道非，寰宇盈魍魎。", "日月不照臨，星辰羞布象。", "每睹萬類心，俱稱上天廣。", "移轉亦何難，夢夢如抱怏。", "地底周雷聲，驕烏絕心想。", "四望如無餘，舉意同羅網。", "安得最高峰，雲外獨來往。"]'),
('4736b195-f9ad-43a8-add4-f0bd23d27000','睡起','許必勝','宋','宋诗','song-poetry','','[]','睡起日滿窗，蒼蠅黄蜂如沸江。',62,'全唐诗/poet.song.122000.json','["睡起日滿窗，蒼蠅黄蜂如沸江。", "莫言閑人得睡足，夢到封侯亦勞碌。", "隔壁棋客時落子，功名事業此中已。", "巫山洛水香成陣，天上曉雲爲翠鬢。"]'),
('215753b4-fd36-4c53-8b33-54aec0201e68','新月','許必勝','宋','宋诗','song-poetry','','[]','偶向樹中見，知從水際生。',48,'全唐诗/poet.song.122000.json','["偶向樹中見，知從水際生。", "葉翻寒不定，雲去意無成。", "亂石流泉影，空山落子聲。", "當年眉黛在，定見可憐情。"]'),
('79103bd9-9215-419f-bd65-e84fba9fcc23','寄山中老稚','許必勝','宋','宋诗','song-poetry','','[]','客久歸無計，家書懶再看。',48,'全唐诗/poet.song.122000.json','["客久歸無計，家書懶再看。", "寄聲花鄭重，爲報竹平安。", "詩酒吾能老，饑寒汝自寬。", "今年新釀熟，收拾釣魚竿。"]'),
('cc4489a4-22bd-4377-a5a0-fce8193fdd2c','閨怨','許必勝','宋','宋诗','song-poetry','','[]','房櫳微雨過，蟲思草根深。',48,'全唐诗/poet.song.122000.json','["房櫳微雨過，蟲思草根深。", "門外青苔色，無人閑到今。", "換衫依暮冷，開鏡倚秋心。", "別意猶能在，應來夢裏尋。"]'),
('23a88fff-12e0-4a3e-8d29-20038978b5b3','贈友山二姪','許必勝','宋','宋诗','song-poetry','','[]','聞道春來解問經，整衣矩步學趨庭。',64,'全唐诗/poet.song.122000.json','["聞道春來解問經，整衣矩步學趨庭。", "雨餘應惜階前蟻，月落休輕案上螢。", "自笑顛毛容我白，且留衰眼爲伊青。", "熟精文選吾家事，早向秋空試鳳翎。"]'),
('cba6268c-53ad-4958-a42d-a43e952e227a','祥符寺得句','許必勝','宋','宋诗','song-poetry','','[]','安蔬自足慰平生，峰靜松閑澗水平。',32,'全唐诗/poet.song.122000.json','["安蔬自足慰平生，峰靜松閑澗水平。", "山意悟時僧不語，落花聲間梵音清。"]'),
('e1c0d801-d885-45e6-baec-0b6042e23d66','題畫','許必勝','宋','宋诗','song-poetry','','[]','傍岸參差筑小亭，山深樹暗水泠泠。',32,'全唐诗/poet.song.122000.json','["傍岸參差筑小亭，山深樹暗水泠泠。", "此間應有神仙語，先向圖中試一聽。"]'),
('6bd5d7cc-1d68-4e9d-8de1-01a0ccc04514','橫秋閣','王駜','宋','宋诗','song-poetry','','[]','地僻無車馬，新凉入醉鄉。',48,'全唐诗/poet.song.122000.json','["地僻無車馬，新凉入醉鄉。", "柳烟顰夕渚，蓮露泣秋塘。", "懶聽能啼雁，閒披古錦囊。", "物華隨處好，何必在瀟湘。"]'),
('e09f0857-5ddc-430c-9226-9e6bc40c713d','句','石安民','宋','宋诗','song-poetry','','[]','明朝江上一回首，二十四峰何處尋。',16,'全唐诗/poet.song.122000.json','["明朝江上一回首，二十四峰何處尋。"]'),
('6b687b67-8548-406b-993f-24b9be97d456','夜聽雙瀑聯句','毛宏','宋','宋诗','song-poetry','','[]','夜靜雙瀑喧，遥聞疑雨來。',72,'全唐诗/poet.song.122000.json','["夜靜雙瀑喧，遥聞疑雨來。", "潤壑生清風，襟宇捐纖埃。", "飛鳴撼半空，暗想飄瓊瑰。", "前觀阻步屧，側耳成徘徊。", "蕭然山館間，此興何悠哉。", "子晉不復見，月白空簫臺。"]'),
('813c78f7-2c66-4ab7-8cb8-edb544eb1f55','句','盧傳霖','宋','宋诗','song-poetry','','[]','寒鄉只顧春來早，暖日暄風盡蕩摩。',16,'全唐诗/poet.song.122000.json','["寒鄉只顧春來早，暖日暄風盡蕩摩。"]'),
('204fb64a-f86e-4240-95b8-3131afd6bf9a','汪端齋聽雨軒','江溥','宋','宋诗','song-poetry','','[]','二蘇當日相思句，故揭名軒意可知。',64,'全唐诗/poet.song.122000.json','["二蘇當日相思句，故揭名軒意可知。", "萱草滿堂長衎衎，棣華聯萼更怡怡。", "酒傾風雨對床夜，夢到池塘覓句時。", "最善君家好兄弟，箇中真樂本無涯。"]'),
('464645e4-8ee1-4466-b6b5-c55d758ef592','曉雲峰','顧岡','宋','宋诗','song-poetry','','[]','一夜乾坤雨乍晴，歸雲無數宿蒼屏。',32,'全唐诗/poet.song.122000.json','["一夜乾坤雨乍晴，歸雲無數宿蒼屏。", "白衣已曬青山曉，茅屋主人猶未醒。"]'),
('8b63196a-4bd0-41ea-a71d-a7bb875a69fc','百福寺薰風堂孝豐縣東門','沈樞','宋','宋诗','song-poetry','','[]','筑室最高處，軒窗八面通。',48,'全唐诗/poet.song.122000.json','["筑室最高處，軒窗八面通。", "鑿山流乳液，開戶納薰風。", "巾履隨凉設，茶瓜與客同。", "我來資解慍，不羨楚王雄。"]'),
('f4b7f2d3-850b-4787-8648-56d2585f26fb','句','沈樞','宋','宋诗','song-poetry','','[]','沽酒頻留客，圍棋不計功。',12,'全唐诗/poet.song.122000.json','["沽酒頻留客，圍棋不計功。"]'),
('5a877692-cacc-432b-972c-eb25a48f967e','同丁致遠司戶游東掖山  其一','李庚','宋','宋诗','song-poetry','','[]','不見詩人老鄭虔，誰知衣鉢此中傳。',32,'全唐诗/poet.song.122000.json','["不見詩人老鄭虔，誰知衣鉢此中傳。", "尚餘傑閣驚人句，更結今秋未了緣。"]'),
('f728615c-8cf2-4302-a8f7-51674f7c2722','同丁致遠司戶游東掖山  其二','李庚','宋','宋诗','song-poetry','','[]','與君共飽桑門飯，愧我曾非蓮社人。',32,'全唐诗/poet.song.122000.json','["與君共飽桑門飯，愧我曾非蓮社人。", "若問生公講堂事，青山門外自橫陳。"]'),
('05dd0fea-f10b-4da2-8154-361740e3d1f7','題尤使君郡圃十二詩 參雲亭','李庚','宋','宋诗','song-poetry','','[]','元公來把麾，與民脫水戹。',48,'全唐诗/poet.song.122000.json','["元公來把麾，與民脫水戹。", "當時游息地，危亭冠州宅。", "梁棟宿寒雲，去天纔一握。", "尚餘手種木，甘棠思邵伯。"]'),
('20adbfd3-847f-42c1-963f-20b2c78259bc','題尤使君郡圃十二詩 雙巖堂','李庚','宋','宋诗','song-poetry','','[]','吾州山水窟，城郭擁寒綠。',48,'全唐诗/poet.song.122000.json','["吾州山水窟，城郭擁寒綠。", "戢戢羣峰間，峙此一雙玉。", "相對如佳賓，可敬不可瀆。", "空翠撲衣裳，夜來雨新沐。"]'),
('329274a2-10b9-467e-bb50-b7a9b1b10b71','題尤使君郡圃十二詩 玉霄亭','李庚','宋','宋诗','song-poetry','','[]','亭亭玉霄峰，列仙皆羽化。',48,'全唐诗/poet.song.122000.json','["亭亭玉霄峰，列仙皆羽化。", "把酒碧桃間，吹簫明月下。", "嗟我落塵凡，鶴背應難跨。", "夫子真癯儒，好上班麟駕。"]'),
('90f04fe6-f99d-4ec1-892b-de1b3dd7e67d','題尤使君郡圃十二詩 匿峰亭','李庚','宋','宋诗','song-poetry','','[]','新亭方半丈，眾山之所宗。',48,'全唐诗/poet.song.122000.json','["新亭方半丈，眾山之所宗。", "慳容半窗月，劣受一簾風。", "傍人笑老子，游戲如兒童。", "亂峰徒頡頏，不與汝爭雄。"]'),
('f6b50414-54e9-40d8-ae06-786d672ae9b6','題尤使君郡圃十二詩 凝思齋','李庚','宋','宋诗','song-poetry','','[]','孫綽賦天台，伻人以圖至。',48,'全唐诗/poet.song.122000.json','["孫綽賦天台，伻人以圖至。", "公今身見之，情親心更醉。", "坐想復行吟，商頌得十二。", "寄語范榮期，金聲重擲地。"]'),
('02bbae21-c5c4-46d1-bf8c-696f37fd0389','題尤使君郡圃十二詩 樂山堂','李庚','宋','宋诗','song-poetry','','[]','青山如避世，詎肯詣公府。',48,'全唐诗/poet.song.122000.json','["青山如避世，詎肯詣公府。", "仁人如好賢，招邀入庭戶。", "拄笏對朝氣，卷簾當暮雨。", "是中有佳趣，莫與兒輩語。"]'),
('15e9d0d5-a5bf-45dd-8075-cf7cc1c96f53','題尤使君郡圃十二詩 清平閣','李庚','宋','宋诗','song-poetry','','[]','彼美東堂下，方池誰鑿成。',48,'全唐诗/poet.song.122000.json','["彼美東堂下，方池誰鑿成。", "蕭侯慨不見，亦足窺典刑。", "湛湛魚可數，怗怗鷗不驚。", "此心有如水，通國號神明。"]'),
('5fa2cbdd-daa7-46b5-8a35-b30f6488146f','題尤使君郡圃十二詩 君子堂','李庚','宋','宋诗','song-poetry','','[]','文簡爲州時，不求赫赫譽。',48,'全唐诗/poet.song.122000.json','["文簡爲州時，不求赫赫譽。", "溫恭君子儒，豈弟民父母。", "黄堂能幾年，清風靄千古。", "願公踵前修，特此相明主。"]'),
('7cd27159-0f14-40fb-87e6-ab5bf8fb8c82','題尤使君郡圃十二詩 靜鎮堂','李庚','宋','宋诗','song-poetry','','[]','海邦本淳古，山民亦顓蒙。',48,'全唐诗/poet.song.122000.json','["海邦本淳古，山民亦顓蒙。", "汝不探赤丸，我無爲缿筩。", "熙熙樵與牧，藹藹春風中。", "何必師齊相，虛堂舍蓋公。"]'),
('3693ed5a-53d3-4ee0-be9c-a61cba8e1c9d','題尤使君郡圃十二詩 霞起堂','李庚','宋','宋诗','song-poetry','','[]','赤城古洞天，彤霞照山谷。',48,'全唐诗/poet.song.122000.json','["赤城古洞天，彤霞照山谷。", "爛爛九光垂，餘輝借草木。", "伊予有痼疾，企望常不足。", "待與馬練師，耘芝灌松竹。"]'),
('49b08c04-d302-4ce2-a170-0c40493363a9','題尤使君郡圃十二詩 駐目亭','李庚','宋','宋诗','song-poetry','','[]','吏散長廊靜，杖藜巾一幅。',48,'全唐诗/poet.song.122000.json','["吏散長廊靜，杖藜巾一幅。", "只圖寬眼界，不管窮脚力。", "野水露微灣，寒山出寸碧。", "待拍洪崖肩，蓬萊真咫尺。"]'),
('9db44680-45bc-4cf6-b288-5b49da12c6c2','題尤使君郡圃十二詩 節愛堂','李庚','宋','宋诗','song-poetry','','[]','吾愛巴揚州，夜不然官燭。',48,'全唐诗/poet.song.122000.json','["吾愛巴揚州，夜不然官燭。", "吾愛陽道州，日炊米二斛。", "使君美無度，力蹈前賢躅。", "宜爾海雲邊，十萬戶蒙福。"]'),
('e7260643-508e-402a-990c-01fb7d2a27ee','題畫扇','李庚','宋','宋诗','song-poetry','','[]','睡起小樓春又殘，半垂雲袖傍欄干。',32,'全唐诗/poet.song.122000.json','["睡起小樓春又殘，半垂雲袖傍欄干。", "楊花飛過鞦韆索，一陣東風作曉寒。"]'),
('dd5de9f0-cc70-48d0-897b-41531a97e6ed','句','李鼎','宋','宋诗','song-poetry','','[]','南流底處所，絳帳居尊嚴。',12,'全唐诗/poet.song.122000.json','["南流底處所，絳帳居尊嚴。"]'),
('a266b1af-604e-4009-8a58-d51f1469d904','壽興國守','李秩','宋','宋诗','song-poetry','','[]','縹緲黄堂擁瑞煙，神光照社記當年。',64,'全唐诗/poet.song.122000.json','["縹緲黄堂擁瑞煙，神光照社記當年。", "風雲慶會千齡際，萸菊佳辰六日前。", "簜節已嘗煩出使，輔藩聊復賴于宣。", "廟堂參贊猶虛位，飛詔行看下九天。"]'),
('1a93c8be-f7b3-43a0-8901-9cd23fd31769','次韻梁尉秦碑','莫濟','宋','宋诗','song-poetry','','[]','六王失國四海歸，秦皇東刻南巡碑。',384,'全唐诗/poet.song.122000.json','["六王失國四海歸，秦皇東刻南巡碑。", "法因史籀有增減，名與蒼頡爭飛馳。", "自言功德可歌頌，黔首箇箇愚無知。", "海神何故獨拒命，風濤塞路蟠蛟螭。", "羣臣諂佞仙藥遠，死生治亂分兩歧。", "山靈不可守碑記，片段應作龜牀支。", "陵谷雖存世代異，耳目雙被誕者欺。", "只餘紙本落人世，千古遺臭東南崖。", "我聞秦望最高峻，城域所見非昔時。", "何山距縣四十里，符合傳記壯且奇。", "眾峰乃是子孫行，古木幾換蛟龍枝。", "指東作西未足怪，父老流傳從小兒。", "政如塗山玉帛會，漫不可考歲久之。", "梁君吏隱年甚少，鬰鬰寸角初解麋。", "裹糧挈榼訪古跡，氣味蕭散如分司。", "忽聞片石在絕頂，小篆無乃斯翁爲。", "手披荆棘訶虎兕，拄杖直叩山頭皮。", "糢糊豈復有字畫，此物及見秦亂離。", "當時威勢振天下，不言慘毒民嗟咨。", "乘輿所至爲刀鋸，方嶽何暇安禮儀。", "關中屢棄百二險，曆數浪指億萬期。", "君臣乃爾自賢聖，鯁論不復相瑕疵。", "陳迹安知百世後，樵夫牧子笑脫頤。", "興亡俄頃三歎息，撫掌重閱太史辭。"]'),
('f3c3155c-7d96-4081-8c15-583b1e1254b7','輓薛常州艮齋先生','莫濟','宋','宋诗','song-poetry','','[]','今代論儒學，如君德最優。',48,'全唐诗/poet.song.122000.json','["今代論儒學，如君德最優。", "是非千古事，出入九家流。", "身歿言猶在，官卑志未酬。", "儻令興禮樂，端不後程仇。"]'),
('1052d701-c386-44b5-83f3-1853b32f459f','縣圃十絕和朱待制  其一','薛抗','宋','宋诗','song-poetry','','[]','春花弄晴風，晝簾垂永日。',24,'全唐诗/poet.song.122000.json','["春花弄晴風，晝簾垂永日。", "公退卧黄紬，放衙頭懶出。"]'),
('f61f9e4c-516f-4c5c-b20c-9af325cbee21','縣圃十絕和朱待制  其二','薛抗','宋','宋诗','song-poetry','','[]','斗牛不能神，梟盧無好采。',24,'全唐诗/poet.song.122000.json','["斗牛不能神，梟盧無好采。", "碌碌甘抱關，誰能媚時宰。"]'),
('140c47d7-0241-4989-8184-fb8ec5ad21f3','縣圃十絕和朱待制  其三','薛抗','宋','宋诗','song-poetry','','[]','二亭巋然立，紫薇爲題顔。',24,'全唐诗/poet.song.122000.json','["二亭巋然立，紫薇爲題顔。", "朝暉射銀鈎，偉觀壓海山。"]'),
('625d140a-1acb-415f-84f6-a72087f00ba2','縣圃十絕和朱待制  其四','薛抗','宋','宋诗','song-poetry','','[]','訟牒如蜂房，未易談笑理。',24,'全唐诗/poet.song.122000.json','["訟牒如蜂房，未易談笑理。", "却思買扁舟，歸釣荆谿水。"]'),
('c44f96d8-e782-4ba8-8b9e-71a856d69874','縣圃十絕和朱待制  其五','薛抗','宋','宋诗','song-poetry','','[]','我無割雞刀，乃當萬家縣。',24,'全唐诗/poet.song.122000.json','["我無割雞刀，乃當萬家縣。", "飛蝗不入境，感謝年穀賤。"]'),
('df32c20b-1446-4aa8-bee8-009b1530e9e5','縣圃十絕和朱待制  其六','薛抗','宋','宋诗','song-poetry','','[]','五斗雖甚微，偃鼠飲滿腹。',24,'全唐诗/poet.song.122000.json','["五斗雖甚微，偃鼠飲滿腹。", "大書歸來賦，有味數過讀。"]'),
('345c1bdc-2ff7-4713-809e-4ca3a1b06bc0','縣圃十絕和朱待制  其七','薛抗','宋','宋诗','song-poetry','','[]','焚香坐清晝，此心自如如。',24,'全唐诗/poet.song.122000.json','["焚香坐清晝，此心自如如。", "我知拙催科，考甘下下書。"]'),
('9e8c91bc-c0bc-4f43-bf0c-60143803c1ad','縣圃十絕和朱待制  其八','薛抗','宋','宋诗','song-poetry','','[]','桐鄉文章伯，我欲執鞭從。',24,'全唐诗/poet.song.122000.json','["桐鄉文章伯，我欲執鞭從。", "明堂選擎天，雲壑卧老松。"]'),
('decd5669-9652-47b1-9512-0020e9b637d7','縣圃十絕和朱待制  其九','薛抗','宋','宋诗','song-poetry','','[]','壽親髮斑斑，綵服老萊戲。',24,'全唐诗/poet.song.122000.json','["壽親髮斑斑，綵服老萊戲。", "欲賦招隱詩，小山念松桂。"]'),
('f52b1ae6-b957-4052-bf3d-03d144a1439b','縣圃十絕和朱待制  其一○','薛抗','宋','宋诗','song-poetry','','[]','援琴鼓流水，絃絕無知音。',24,'全唐诗/poet.song.122000.json','["援琴鼓流水，絃絕無知音。", "爲語逐臭夫，蘭芷生深林。"]'),
('df111286-348d-4bfb-8f7d-f67597e44c40','邵武  其一','葉儀鳳','宋','宋诗','song-poetry','','[]','溪上千峰碧玉環，瞰溪臺榭紫雲間。',32,'全唐诗/poet.song.122000.json','["溪上千峰碧玉環，瞰溪臺榭紫雲間。", "鳥啼花落非人世，似在金鼇山上山。"]'),
('1c6fe439-c3d6-45fc-abe2-7f3f8376b0bb','邵武  其二','葉儀鳳','宋','宋诗','song-poetry','','[]','城南城北草如茵，綠水青山眼界新。',32,'全唐诗/poet.song.122000.json','["城南城北草如茵，綠水青山眼界新。", "更問樵溪何處是，滿城桃李萬家春。"]'),
('8ab2b176-90db-4ed8-99d9-1c1b0ae122c7','句','葉儀鳳','宋','宋诗','song-poetry','','[]','天鍾秀氣魁文陛，地湧仙源接武夷。',16,'全唐诗/poet.song.122000.json','["天鍾秀氣魁文陛，地湧仙源接武夷。"]'),
('3d21a75a-eca5-489e-b176-b41cda2bcf86','題石橋','林仰','宋','宋诗','song-poetry','','[]','空山風露洗秋容，萬里陰晴此夕同。',32,'全唐诗/poet.song.122000.json','["空山風露洗秋容，萬里陰晴此夕同。", "袖取碧巖邀月手，石橋來謁化人宮。"]'),
('6a48be4b-dc69-4385-94db-7f25a9f7b886','劉阮祠','林仰','宋','宋诗','song-poetry','','[]','深樹冥冥一徑風，溪流應與十洲通。',32,'全唐诗/poet.song.122000.json','["深樹冥冥一徑風，溪流應與十洲通。", "仙家日月無人識，只愛桃花二月紅。"]'),
('fabe4970-56d4-4b65-87bc-136de980f051','赴官武康投宿客邸作','林仰','宋','宋诗','song-poetry','','[]','巾子山頭一枕風，皇華亭下水連空。',32,'全唐诗/poet.song.122000.json','["巾子山頭一枕風，皇華亭下水連空。", "山靈不用回俗駕，儻有田園吾欲東。"]'),
('b926bf09-bb4a-422d-9423-3ae497254307','金臺寺','林仰','宋','宋诗','song-poetry','','[]','蒼蘚沿階走細泉，青松翠竹照華軒。',64,'全唐诗/poet.song.122000.json','["蒼蘚沿階走細泉，青松翠竹照華軒。", "高人倦作金毛吼，旅客來參玉版禪。", "暖日遲遲晞宿露，微風淡淡逐寒烟。", "茶甌香秘蒲團穩，始覺林泉思邈然。"]'),
('3801f0d7-1e11-4df6-83db-f92f7249573e','題天台福聖觀瀑布','楊偰','宋','宋诗','song-poetry','','[]','積雪懸崖照幽谷，轟雷破石響空山。',32,'全唐诗/poet.song.122000.json','["積雪懸崖照幽谷，轟雷破石響空山。", "直疑天上銀河水，倒瀉千巖萬壑間。"]'),
('574b6b19-7e4c-4006-b529-8fc6fea30774','紹興己巳游洞霄','楊偰','宋','宋诗','song-poetry','','[]','青山九鎖隔凡緣，福地潜通小有天。',64,'全唐诗/poet.song.122000.json','["青山九鎖隔凡緣，福地潜通小有天。", "古洞落花春寂寂，空山亂石水涓涓。", "金丹翠箬藏千歲，芝草瑯玕定幾年。", "惆悵何時謝塵事，山中長作地行仙。"]'),
('75fa5539-d081-43ef-a061-aa3f66994081','夜宿龍頭','楊汝南','宋','宋诗','song-poetry','','[]','江流如箭路如梯，夜泊龍頭煙靄迷。',32,'全唐诗/poet.song.122000.json','["江流如箭路如梯，夜泊龍頭煙靄迷。", "兩角孤雲天一握，曉光不覺玉繩低。"]'),
('f5480e36-4938-4610-9e7c-10d517f7cc22','挽郭彥鄒','劉度','宋','宋诗','song-poetry','','[]','孝友追前輩，雍容具典刑。',48,'全唐诗/poet.song.122000.json','["孝友追前輩，雍容具典刑。", "人榮老萊服，天隕少微星。", "玉潤聯三傑，金籝擅一經。", "平生墊巾操，不愧伯恭銘。"]'),
('6392c78c-f324-4887-a465-24abf4d3f7ae','妙峰庵','羅鞏','宋','宋诗','song-poetry','','[]','龍山僧舍多，亦自少佳處。',84,'全唐诗/poet.song.122000.json','["龍山僧舍多，亦自少佳處。", "妙峰正可人，正以深遠故。", "我行困炎歊，肩輿特紆路。", "穿林入幽洞，木石尤怪古。", "颯颯清風來，忻然愜勝趣。", "耆閣有老禪，恨未款語晤。", "即對石蓮池，一誦碧雲句。"]'),
('a00fa346-9243-49e8-8e82-0da3a2b08307','永安寺遇父老','羅鞏','宋','宋诗','song-poetry','','[]','複水橫山清且長，絃歌亹亹過黌堂。',32,'全唐诗/poet.song.122000.json','["複水橫山清且長，絃歌亹亹過黌堂。", "相迎父老爭冠带，自是涇川禮義鄉。"]'),
('f6551f3f-935b-438b-8bd7-0e9ddbf422d0','黄巖縣樓','鄭伯熊','宋','宋诗','song-poetry','','[]','飛甍鬰崢嶸，萬井交錯綜。',84,'全唐诗/poet.song.122000.json','["飛甍鬰崢嶸，萬井交錯綜。", "俯仰各有則，靜以御羣動。", "平時心匠微，斤斧袖不用。", "少施見其餘，規畫已驚眾。", "姬公昔營洛，道德作梁棟。", "東家有餘材，鳳衰無復夢。", "帝方議明堂，行矣與君共。"]'),
('b6284b0a-fdb7-454d-8f64-515e615183b0','清畏軒','鄭伯熊','宋','宋诗','song-poetry','','[]','樹蕙餘百畝，藝蘭當路岐。',72,'全唐诗/poet.song.122000.json','["樹蕙餘百畝，藝蘭當路岐。", "清風一披拂，香氣無不之。", "紉爲楚纍佩，辱我幽靚姿。", "小草生澗底，雨露無恩私。", "不入兒女玩，歲晚得自持。", "所以古君子，清德畏人知。"]'),
('b94424ef-6a88-4bf2-92e3-8a61fd31c916','過萬年山望羅漢嶺上大松','鄭伯熊','宋','宋诗','song-poetry','','[]','蒼髯白甲老煙雲，萬木叢中獨挺身。',32,'全唐诗/poet.song.122000.json','["蒼髯白甲老煙雲，萬木叢中獨挺身。", "一柱擎天須此物，執柯它日屬何人。"]'),
('8d610379-5df5-41d2-b45e-e67098d6a622','問津樓','鄭伯熊','宋','宋诗','song-poetry','','[]','周道直如矢，亡羊古無有。',84,'全唐诗/poet.song.122000.json','["周道直如矢，亡羊古無有。", "利欲蝕本心，眼花大如斗。", "適燕南其轅，之越乃北走。", "四海阮嗣宗，臧否不掛口。", "一慟激流俗，新荑發枯朽。", "斯人向千載，此意誰復剖。", "問津非名樓，端以覺蒙蔀。"]'),
('b4ad9ecc-4fd7-4767-9403-8d684a1439ad','枕上','鄭伯熊','宋','宋诗','song-poetry','','[]','飄風不崇朝，驟雨不終日。',96,'全唐诗/poet.song.122000.json','["飄風不崇朝，驟雨不終日。", "清寒入絺綌，御袷有餘鬰。", "天時不能調，人事那可必。", "清燈耿孤窗，萬籟助飀飄。", "憂愁從中來，起坐髮屢櫛。", "丈夫屬有念，功名乃餘物。", "突兀萬間屋，此意何時畢。", "長吟答寒螿，四壁轉蕭瑟。"]'),
('5de2e279-65dc-4db1-90a8-491a97511239','北園送關簡州分得古字','鄭伯熊','宋','宋诗','song-poetry','','[]','我歌白雲篇，送君水雲浦。',120,'全唐诗/poet.song.122000.json','["我歌白雲篇，送君水雲浦。", "歌罷水雲寒，佇立聽鳴艣。", "江湖昔在手，短簑釣煙雨。", "軒裳誤羈馽，濫趨羣玉府。", "朱墨浪自妍，筆削竟何補。", "高鴻墮秋枕，歸夢紛莫數。", "著鞭輸子先，寤歌獨懷古。", "中年况作別，心事復誰吐。", "故人分龍符，江色映修組。", "話舊定何時，新知日旁午。"]'),
('696e20d3-fc80-47e2-9e12-1a09c23cf417','次韵陳倅瑞巖之什','鄭伯熊','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','詩到南昌老更奇，固知流派自江西。',64,'全唐诗/poet.song.122000.json','["詩到南昌老更奇，固知流派自江西。", "滕王閣下秋濤壯，孺子堂前春鳥啼。", "我似癡蠅思驥尾，君如野鶴趁雞栖。", "十年翰墨元猶白，不識微言爲指迷。"]'),
('a4e86824-1831-4890-b883-a78d613ef869','四月十四日至廣陵','鄭伯熊','宋','宋诗','song-poetry','','[]','春歸村塢綠陰迷，又向山腰轉馬蹄。',64,'全唐诗/poet.song.122000.json','["春歸村塢綠陰迷，又向山腰轉馬蹄。", "收盡雪芳猶採擷，割殘雲穗再扶犂。", "鄉謠到處無音律，野飯黄昏只筍虀。", "惟有客愁消不得，隔溪篁竹子規啼。"]'),
('101c45c0-db21-4f88-b458-65887550b087','婺舟道中','鄭伯熊','宋','宋诗','song-poetry','','[]','筍輿時得並溪行，溪水秋來似鑑清。',32,'全唐诗/poet.song.122000.json','["筍輿時得並溪行，溪水秋來似鑑清。", "仰春雲山勞眼力，臨流照眼却分明。"]'),
('0db7c506-9bd4-4ece-8290-9b72f385a26d','句','鄭伯熊','宋','宋诗','song-poetry','','[]','胡牀倚春風，池亭自花柳。',12,'全唐诗/poet.song.122000.json','["胡牀倚春風，池亭自花柳。"]'),
('29a05833-7683-4954-84ad-0271d20b64dd','冷泉亭','徐涓','宋','宋诗','song-poetry','','[]','畏日炎炎爍太虛，倚欄冰雪冷生膚。',32,'全唐诗/poet.song.122000.json','["畏日炎炎爍太虛，倚欄冰雪冷生膚。", "百川萬壑非無水，洗得人間熱惱無。"]'),
('e4af3acf-ffbe-47b7-a28f-40d3d1775f6c','紹興乙丑七月幕谷游何蕭卿乘月獨遊淡巖書事兼簡零陵宰君李兄秀實','游何','宋','宋诗','song-poetry','','[]','渡過瀟江日已曛，影和明月共三人。',64,'全唐诗/poet.song.122000.json','["渡過瀟江日已曛，影和明月共三人。", "名巖近郭別州少，好事更誰如我真。", "絕頂有天浮碧樹，凌秋無暑斷紅塵。", "終當早棄人間事，來與山僧作並鄰。"]'),
('9a4ac155-12b4-4ee9-b8af-08db6217f14b','紹興乙丑秋仲冒雨獨游陽華巖勝絕未讓淡山巖恨古今詩人未有奇句潏上游何臨清流以賦之且棕鞋桐帽悵不一陪浮溪先生金華居士以徜徉','游何','宋','宋诗','song-poetry','','[]','西風卷癡雲，欲壓不墮地。',204,'全唐诗/poet.song.122000.json','["西風卷癡雲，欲壓不墮地。", "化作碧孱顔，融結在空際。", "是名陽華巖，造物一何異。", "東山雨脚斷，明月招我至。", "傍窺嵌竇深，密恐鬼神閟。", "細度泬寥風，舊無卑濕氣。", "虛閣架其中，榜以浮嵐美。", "下有潺湲谿，翻雪轟雷比。", "閣背兩橋分，巖脇雙龍起。", "石如纓絡垂，整整翠緌委。", "又如鼙鼓形，撾擊聲頗厲。", "溪水相與喧，鏜鞈亂宮徵。", "巖窮天忽開，木杪風自靡。", "坐久髮毛寒，興逸詩語綺。", "無人共一尊，有客自千里。", "山僧頗慇勤，相伴亦忘寐。", "拂石要題詩，揮毫留漢隸。"]'),
('9ac09621-a236-44f1-8a8f-bac5838800e3','晚歸','吳沆','宋','宋诗','song-poetry','','[]','夕陽西欲沒，宛轉山氣昏。',48,'全唐诗/poet.song.122000.json','["夕陽西欲沒，宛轉山氣昏。", "獨逝頗無累，時欣暗經林。", "棲鳥未穩集，歸馬無奔聲。", "恍忽自得意，興來誰與言。"]'),
('8e938b88-1561-4741-80c8-ebebcb05bef5','早行','吳沆','宋','宋诗','song-poetry','','[]','晨風集微和，曉色動佳氣。',96,'全唐诗/poet.song.122000.json','["晨風集微和，曉色動佳氣。", "溟溟四郊烟，漠漠一川水。", "前村雞犬喧，遠樹鳥雀喜。", "山腰客行來，林下雉驚起。", "時聞牧童謠，不見騎牛至。", "回頭望東隅，曉日粲光麗。", "胸襟倏暄煩，敗我幽靜意。", "行行載馳驅，已復到城市。"]'),
('4168f183-c074-4dfc-84f9-2ee7bdce318b','曉晴','吳沆','宋','宋诗','song-poetry','','[]','夜半雨忽作，朝來雲又晴。',48,'全唐诗/poet.song.122000.json','["夜半雨忽作，朝來雲又晴。", "林花洗幽艷，池水湛虛明。", "草色侵衣濕，山光入座清。", "茅簷正幽寂，啼鳥兩三聲。"]'),
('e126c2d4-e452-4458-9c7c-9a9d85e45b31','野外','吳沆','宋','宋诗','song-poetry','','[]','野外望中闊，遥山宛轉隨。',48,'全唐诗/poet.song.122000.json','["野外望中闊，遥山宛轉隨。", "小溪芳草合，高樹古藤垂。", "鳥過驚風疾，雲行度嶺遲。", "回頭失歸路，還問老農知。"]'),
('05802d08-45c0-48f4-8b99-842ea9716b3c','岳陽作','吳沆','宋','宋诗','song-poetry','','[]','歲暮懷家客，通宵不自娛。',48,'全唐诗/poet.song.122000.json','["歲暮懷家客，通宵不自娛。", "諸兄得意否，老母有歡無。", "已謝交朋遠，猶思弟妹孤。", "吾身不足念，爲此一嗟吁。"]'),
('d5c430a4-d8b2-44ac-b81e-68c07418a1f4','友人趨寧化','吳沆','宋','宋诗','song-poetry','','[]','聞君早晚趨寧化，尚有新詩別故人。',64,'全唐诗/poet.song.122000.json','["聞君早晚趨寧化，尚有新詩別故人。", "試問幾程端可到，還憂半載不相親。", "傷心歲律崢嶸暮，解事梅花摘索新。", "去去冰霜頻莫厭，庭闈和氣即如春。"]'),
('0758bec6-89a9-4c57-9628-996d634389b0','以易授玭有契於予心喜而成詩','吳沆','宋','宋诗','song-poetry','','[]','早日功名世背馳，擬將文字療寒饑。',64,'全唐诗/poet.song.122000.json','["早日功名世背馳，擬將文字療寒饑。", "雖無杜甫驚人句，庶免淵明責子詩。", "總角宜興俱脫穎，含哺應惠尚兒癡。", "殷勤謝爾傳心印，解後靈椿見五枝。"]'),
('95351974-f65f-4361-8d11-36cf5d5f0ca9','春遊吟','吳沆','宋','宋诗','song-poetry','','[]','鳥語烟光裏，人行草色中。',24,'全唐诗/poet.song.122000.json','["鳥語烟光裏，人行草色中。", "池邊忽分散，花下復相逢。"]'),
('104706f6-d582-4c55-9ffe-af58c3337185','首夏','吳沆','宋','宋诗','song-poetry','','[]','積雨有餘潤，遊雲無定陰。',24,'全唐诗/poet.song.122000.json','["積雨有餘潤，遊雲無定陰。", "燕飛華屋靜，鶯囀碧窗深。"]'),
('bb298d74-c79a-479f-b504-6a48526d1440','折花','吳沆','宋','宋诗','song-poetry','','[]','野花開處客徘徊，胡蝶摶飛歛復開。',32,'全唐诗/poet.song.122000.json','["野花開處客徘徊，胡蝶摶飛歛復開。", "折得野花隨手去，不知胡蝶逐人來。"]'),
('bb4a9c91-35bb-41c4-986d-61a3c6e1d32d','臨高臺  其一','吳沆','宋','宋诗','song-poetry','','[]','高高軒楹日照東，扶桑柱植西崑崙。',124,'全唐诗/poet.song.122000.json','["高高軒楹日照東，扶桑柱植西崑崙。", "上有明真紫霞客，廝征伯僑役羨門。", "月馭叱前驅，風駟殿後奔。", "靈衣披披溘晻靄，玉斧斷斷除煩冤。", "虛皇下兩耳，授以金簡文。", "相觀峻極不容步，擬軼清氣排重閽。", "嚥日誦黄庭，滴露抄韋編。", "羊歧之亡罔象得，蠻觸之角醯雞天，臨臺一笑俱超然。"]'),
('fb683cd9-2d46-4f5b-bd80-9e7d76411e1c','臨高臺  其二','吳沆','宋','宋诗','song-poetry','','[]','高筑黄金貯俊才，雲關玉鎖問誰開。',32,'全唐诗/poet.song.122000.json','["高筑黄金貯俊才，雲關玉鎖問誰開。", "若非倚賴東風力，安得憑虛直上來。"]'),
('5bb595fe-bb33-4287-b9b4-324db608dda6','臨高臺  其三','吳沆','宋','宋诗','song-poetry','','[]','高臺跨崇岡，簷宇鎖空霧。',72,'全唐诗/poet.song.122000.json','["高臺跨崇岡，簷宇鎖空霧。", "新晴洗雙目，十里在跬步。", "霏霏漁浦煙，冉冉富春樹。", "風花不我私，何以理愁緒。", "誰梳白玉窗，中有浮雲度。", "浮雲吹不開，不見行人去。"]'),
('bb841d0c-41b5-4487-92aa-280cbf8074dd','三清山','吳沆','宋','宋诗','song-poetry','','[]','選勝園林興未闌，拏舟飛出小溪灣。',64,'全唐诗/poet.song.122000.json','["選勝園林興未闌，拏舟飛出小溪灣。", "光摇一碧回環水，翠挹三清遠近山。", "似惜雨晴天恰好，真忘名利日長閑。", "松筠不鎖神仙境，携得煙霞滿袖還。"]'),
('12bb45fa-bd29-4af1-baa0-0d7c6c346874','句  其一','吳沆','宋','宋诗','song-poetry','','[]','樹頭明月光欲吐，反眼仰面天恢恢。',16,'全唐诗/poet.song.122000.json','["樹頭明月光欲吐，反眼仰面天恢恢。"]'),
('7b473604-3f74-4eef-90d1-893985328a90','句  其二','吳沆','宋','宋诗','song-poetry','','[]','隙風無端吹我燭，滿窗明月心更清。',16,'全唐诗/poet.song.122000.json','["隙風無端吹我燭，滿窗明月心更清。"]'),
('2c835fad-b90f-45a1-9f4a-fedb0d2962d1','句  其三','吳沆','宋','宋诗','song-poetry','','[]','江流回轉石不移，釣絲卷盡生鬚絲。',16,'全唐诗/poet.song.122000.json','["江流回轉石不移，釣絲卷盡生鬚絲。"]'),
('d86c1288-c543-4671-adea-c5a788a5fc87','句  其四','吳沆','宋','宋诗','song-poetry','','[]','爲兵不願作刀鋸，刑人未必皆不忠。',32,'全唐诗/poet.song.122000.json','["爲兵不願作刀鋸，刑人未必皆不忠。", "爲器不願作鐘鼎，銘勳未爲皆有功。"]'),
('1fb599d5-53e8-45d4-8490-210e391fabfe','句  其五','吳沆','宋','宋诗','song-poetry','','[]','耳根靜處水流村，眼界空時山在門。',16,'全唐诗/poet.song.122000.json','["耳根靜處水流村，眼界空時山在門。"]'),
('b6469c9d-95f8-4caa-b327-02bed56049bf','句  其六','吳沆','宋','宋诗','song-poetry','','[]','燕忙將入夏，蠶暖正眠春。',12,'全唐诗/poet.song.122000.json','["燕忙將入夏，蠶暖正眠春。"]'),
('5572400a-8b1e-4067-bc5a-1670bfdac5e7','句  其七','吳沆','宋','宋诗','song-poetry','','[]','水痕纔破臘，雲黯似知春。',12,'全唐诗/poet.song.122000.json','["水痕纔破臘，雲黯似知春。"]'),
('db600f66-760b-4a23-b3c3-b5574bf23768','句  其八','吳沆','宋','宋诗','song-poetry','','[]','聖主思文德，元臣獻武功。',106,'全唐诗/poet.song.122000.json','["聖主思文德，元臣獻武功。", "一言深悟主，五利且和戎。", "……天地包羞日，山河匿怨中。", "……儒生別有淚，不是哭途窮。", "……戰伐功何有，和親計未疏。", "將軍休抵掌，隱忍待驅除。", "……氛祲埋金闕，塵沙暝梓宮。", "……古來嘗膽事，泣血望羣公。"]'),
('b9c0eff0-b0ab-460d-bffe-1370e07964a1','句  其九','吳沆','宋','宋诗','song-poetry','','[]','江淮十載警胡塵，底事磨崖未勒勳。',32,'全唐诗/poet.song.122000.json','["江淮十載警胡塵，底事磨崖未勒勳。", "聞道本朝還遣使，且令諸將各收軍。"]'),
('29e07d93-836e-4b41-b426-f84c6f326180','句  其一○','吳沆','宋','宋诗','song-poetry','','[]','寇殘井邑困流離，回首歡娛一一悲。',32,'全唐诗/poet.song.122000.json','["寇殘井邑困流離，回首歡娛一一悲。", "不厭兒童遭世亂，惟愁父老說清時。"]'),
('07255800-5fcc-4052-ad96-f05eda64d74b','句  其一一','吳沆','宋','宋诗','song-poetry','','[]','萬井火熬波裏雪，十州雷送雨前春。',16,'全唐诗/poet.song.122000.json','["萬井火熬波裏雪，十州雷送雨前春。"]'),
('ebbbfcdb-8574-4258-b4b4-fd3765b4a1b6','句  其一二','吳沆','宋','宋诗','song-poetry','','[]','亂石分開急流水，羣山擁出最高峰。',16,'全唐诗/poet.song.122000.json','["亂石分開急流水，羣山擁出最高峰。"]'),
('b32b33d7-5cfb-4ba8-b819-458fff0b03f9','句  其一三','吳沆','宋','宋诗','song-poetry','','[]','山高不改自然色，水遠能流無盡聲。',16,'全唐诗/poet.song.122000.json','["山高不改自然色，水遠能流無盡聲。"]'),
('690c1853-f6b6-485c-910f-664b2a437686','句  其一四','吳沆','宋','宋诗','song-poetry','','[]','木落青無影，荷枯澹有香。',12,'全唐诗/poet.song.122000.json','["木落青無影，荷枯澹有香。"]'),
('324cec7c-98a2-4713-8b8f-fe8c31935d68','句  其一五','吳沆','宋','宋诗','song-poetry','','[]','行杯波動金蓮側，剪燼燈飄寶蠟殘。',16,'全唐诗/poet.song.122000.json','["行杯波動金蓮側，剪燼燈飄寶蠟殘。"]'),
('6b222611-d8e7-4a35-b32a-fcf0040d60f6','句  其一六','吳沆','宋','宋诗','song-poetry','','[]','西風橫吹雨脚斷，秋雲輕籠日花明。',16,'全唐诗/poet.song.122000.json','["西風橫吹雨脚斷，秋雲輕籠日花明。"]'),
('29740eaa-e449-4ded-ac74-9e431d6333af','句  其一七','吳沆','宋','宋诗','song-poetry','','[]','君少作奇字，瘦硬得柳骨。',62,'全唐诗/poet.song.122000.json','["君少作奇字，瘦硬得柳骨。", "墨凈剪水勻，勢健拗鐵屈。", "……新詩更鎸磨，勁絕與字匹。", "老蛟寒卧波，壯士努抉石。", "翻盆勢動摇，詩與字俱力。"]'),
('70463522-3eea-4b62-a8eb-cf926db02d5d','句  其一八','吳沆','宋','宋诗','song-poetry','','[]','樵歌催日晚，村樂見年豐。',26,'全唐诗/poet.song.122000.json','["樵歌催日晚，村樂見年豐。", "……雁陣橫沖霧，酒軍酣戰風。"]'),
('49e4a8cc-bf57-495b-baa9-6e78bf3baab8','句  其一九','吳沆','宋','宋诗','song-poetry','','[]','羽衛連荆棘，衣冠雜虎狼。',38,'全唐诗/poet.song.122000.json','["羽衛連荆棘，衣冠雜虎狼。", "烟沉鳧雁斷，天闊水雲黄。", "……風悲雲動色，天慘日無光。"]'),
('e8a75e43-ca28-4462-a387-6211b1f918d3','句  其二○','吳沆','宋','宋诗','song-poetry','','[]','霜皮圍四十，水擊黑三千。',190,'全唐诗/poet.song.122000.json','["霜皮圍四十，水擊黑三千。", "……山河歸整頓，天地入陶甄。", "……但存忠貫日，未問寫凌烟。", "……遠吸金莖露，高攀玉井蓮。", "……風度優囊笏，恩光遶賜鞭。", "……李唐光夾日，炎漢赫中天。", "……共承天柱折，獨斡斗杓旋。", "……懷古歌鴻雁，傷今拜杜鵑。", "……王氣周旋內，胡塵笑語邊。", "……浮雲開斥堠，飛鳥避戈鋋。", "……蜀道開天險，雄誇億萬年。", "停空蟠瑞氣，蓋代出真賢。", "……國多艱難盡，公歸早晚遄。", "願爲元結頌，磨石待高鎸。"]'),
('0e742471-11ad-411a-aae3-16046ea9b937','句  其二一','吳沆','宋','宋诗','song-poetry','','[]','厭看花笑客，忍受草欺人。',12,'全唐诗/poet.song.122000.json','["厭看花笑客，忍受草欺人。"]'),
('779ca3e9-98a2-4f61-b588-e15b67445330','句  其二二','吳沆','宋','宋诗','song-poetry','','[]','水流成獨往，山勢作朋來。',12,'全唐诗/poet.song.122000.json','["水流成獨往，山勢作朋來。"]'),
